                                                        <span className="whitespace-nowrap font-black">13 500 DZD</span>
                                                    </div>
                                                    <div className="text-[11px] mt-0.5 space-y-0.5 bg-gray-100 p-1.5 rounded-md font-bold">
                                                        <p>[CODE 1/3]: P8X2-L9M3-QW12</p>
                                                        <p>[CODE 2/3]: Z4V7-K0J5-RT99</p>
                                                        <p>[CODE 3/3]: N1Y4-U6B8-GH44</p>
                                                    </div>
                                                </div>
                                            </div>

                                            <div className="border-t border-dashed border-black pt-4 mb-6 text-center text-black">
                                                <p className="text-[10px] uppercase tracking-[0.2em] font-bold">Total à payer</p>
                                                <p className="text-2xl font-black mt-1">15 000 DZD</p>
                                            </div>

                                            <div className="text-center italic text-[11px] leading-snug text-black">
                                                {footerMessage.split('\n').map((line, i) => (
                                                    <p key={i}>{line}</p>
                                                ))}
                                                <div className="mt-4 opacity-50 font-bold">
                                                    <p>**** FIN DU TICKET ****</p>
                                                </div>
                                            </div>
                                        </div>

                                        <div className="mt-12 text-slate-500 text-xs font-bold flex items-center gap-2 uppercase tracking-widest">
                                            <span className="material-symbols-outlined text-sm">info</span>
                                            L&apos;aperçu est mis à jour en temps réel

                                        </div>
                                    </div>
                                </section>
                            </div>
                        </div>
                    )}

                    {activeTab === "appearance" && (
                        <div className="max-w-4xl space-y-12 animate-in fade-in slide-in-from-bottom-2 duration-300">
                            {/* Section: Couleur d'accentuation */}
                            <section className="space-y-6">
                                <div className="flex flex-col gap-1">
                                    <h2 className="text-xl font-bold text-white">Couleur d&apos;accentuation</h2>

                                    <p className="text-sm text-slate-400">Personnalisez la couleur principale de votre interface admin.</p>
                                </div>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-8 items-start">
                                    <div className="space-y-6">
                                        <div className="flex flex-wrap gap-4 items-center">
                                            <button onClick={() => setAccentColor("#ec5b13")} className={`w-10 h-10 rounded-full bg-[#ec5b13] transition-all hover:scale-110 shrink-0 ${accentColor === "#ec5b13" ? "border-4 border-white/20 ring-2 ring-[#ec5b13] ring-offset-4 ring-offset-[#0f0d0c]" : ""}`}></button>
                                            <button onClick={() => setAccentColor("#4169e1")} className={`w-10 h-10 rounded-full bg-[#4169e1] transition-all hover:scale-110 shrink-0 ${accentColor === "#4169e1" ? "border-4 border-white/20 ring-2 ring-[#4169e1] ring-offset-4 ring-offset-[#0f0d0c]" : ""}`}></button>
                                            <button onClick={() => setAccentColor("#10b981")} className={`w-10 h-10 rounded-full bg-[#10b981] transition-all hover:scale-110 shrink-0 ${accentColor === "#10b981" ? "border-4 border-white/20 ring-2 ring-[#10b981] ring-offset-4 ring-offset-[#0f0d0c]" : ""}`}></button>
                                            <button onClick={() => setAccentColor("#8b5cf6")} className={`w-10 h-10 rounded-full bg-[#8b5cf6] transition-all hover:scale-110 shrink-0 ${accentColor === "#8b5cf6" ? "border-4 border-white/20 ring-2 ring-[#8b5cf6] ring-offset-4 ring-offset-[#0f0d0c]" : ""}`}></button>
                                            <button onClick={() => setAccentColor("#ef4444")} className={`w-10 h-10 rounded-full bg-[#ef4444] transition-all hover:scale-110 shrink-0 ${accentColor === "#ef4444" ? "border-4 border-white/20 ring-2 ring-[#ef4444] ring-offset-4 ring-offset-[#0f0d0c]" : ""}`}></button>
                                        </div>
                                        <div className="max-w-xs">
                                            <label className="block text-xs font-bold uppercase tracking-wider text-slate-500 mb-2">Code Hexadécimal</label>
                                            <div className="relative flex items-center group">
                                                <span className="absolute left-3 text-slate-400 group-focus-within:text-[#ec5b13] transition-colors">#</span>
                                                <input
                                                    className="w-full bg-[#1a1614] border border-[#2d2622] rounded-xl pl-7 pr-12 py-3 text-white focus:ring-1 focus:ring-[#ec5b13] focus:border-[#ec5b13] outline-none transition-all"
                                                    type="text"
                                                    value={accentColor.replace('#', '')}
                                                    onChange={(e) => setAccentColor('#' + e.target.value)}
                                                />
                                                <span className="material-symbols-outlined absolute right-3 text-slate-400 cursor-pointer hover:text-white shrink-0">palette</span>
                                            </div>
                                        </div>
                                    </div>
                                    {/* Preview Area */}
                                    <div className="p-6 bg-[#1a1614]/50 border border-[#2d2622] rounded-2xl flex flex-col items-center justify-center gap-6">
                                        <span className="text-xs font-bold uppercase tracking-widest text-slate-500">Aperçu en direct</span>
                                        <div className="flex flex-col items-center gap-4">
                                            <button className="bg-[#ec5b13] hover:bg-[#ec5b13]/90 text-white px-6 py-2.5 rounded-xl font-bold shadow-lg shadow-[#ec5b13]/20 transition-all shrink-0">
                                                Bouton Primaire
                                            </button>
                                            <span className="px-3 py-1 bg-[#ec5b13]/20 text-[#ec5b13] text-xs font-bold rounded-full border border-[#ec5b13]/30 shrink-0">
                                                Badge Actif
                                            </span>
                                        </div>
                                    </div>
                                </div>
                            </section>

                            <hr className="border-[#2d2622]" />

                            {/* Section: Logos et Icônes */}
                            <section className="space-y-6">
                                <div className="flex flex-col gap-1">
                                    <h2 className="text-xl font-bold text-white">Logos et Icônes</h2>
                                    <p className="text-sm text-slate-400">Importez vos éléments visuels pour une interface à votre image.</p>
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
                                    {/* Dark Dashboard Logo */}
                                    <div
                                        onClick={() => dashboardLogoInputRef.current?.click()}
                                        className="group relative flex flex-col items-center justify-center p-6 bg-[#1a1614] border-2 border-dashed border-[#2d2622] hover:border-[#ec5b13]/50 rounded-2xl transition-all cursor-pointer overflow-hidden"
                                    >
                                        <input
                                            type="file"
                                            ref={dashboardLogoInputRef}
                                            className="hidden"
                                            accept="image/*"
                                            onChange={(e) => handleLogoFileChange(e, 'dashboard')}
                                        />
                                        {isUploadingDashboardLogo ? (
                                            <Loader2 className="animate-spin text-[#ec5b13] size-8 mb-3" />
                                        ) : dashboardLogoUrl ? (
                                            <div className="mb-3 h-12 flex items-center justify-center w-full">
                                                <img src={dashboardLogoUrl} className="h-full w-auto object-contain" alt="Dashboard Logo" />
                                            </div>
                                        ) : (
                                            <span className="material-symbols-outlined text-3xl text-slate-500 group-hover:text-[#ec5b13] mb-3">upload_file</span>
                                        )}
                                        <span className="text-xs font-bold text-center text-slate-300">Logo Dashboard (Dark)</span>
                                        <span className="text-[10px] text-slate-500 mt-1 uppercase">SVG, PNG (Max 2MB)</span>
                                    </div>

                                    {/* Light Terminal Logo */}
                                    <div
                                        onClick={() => logoInputRef.current?.click()}
                                        className="group relative flex flex-col items-center justify-center p-6 bg-white/5 border-2 border-dashed border-[#2d2622] hover:border-[#ec5b13]/50 rounded-2xl transition-all cursor-pointer overflow-hidden"
                                    >
                                        {isUploadingLogo ? (
                                            <Loader2 className="animate-spin text-[#ec5b13] size-8 mb-3" />
                                        ) : logoUrl ? (
                                            <div className="mb-3 h-12 flex items-center justify-center w-full">
                                                <img src={logoUrl} className="h-full w-auto object-contain" alt="Terminal Logo" />
                                            </div>
                                        ) : (
                                            <span className="material-symbols-outlined text-3xl text-slate-500 group-hover:text-[#ec5b13] mb-3">upload_file</span>
                                        )}
                                        <span className="text-xs font-bold text-center text-slate-300">Logo Borne Client (Light)</span>
                                        <span className="text-[10px] text-slate-500 mt-1 uppercase">SVG, PNG (Max 2MB)</span>
                                    </div>

                                    {/* Favicon */}
                                    <div
                                        onClick={() => faviconInputRef.current?.click()}
                                        className="group relative flex flex-col items-center justify-center p-6 bg-[#1a1614] border-2 border-dashed border-[#2d2622] hover:border-[#ec5b13]/50 rounded-2xl transition-all cursor-pointer overflow-hidden"
                                    >
                                        <input
                                            type="file"
                                            ref={faviconInputRef}
                                            className="hidden"
                                            accept="image/*"
                                            onChange={(e) => handleLogoFileChange(e, 'favicon')}
                                        />
                                        {isUploadingFavicon ? (
                                            <Loader2 className="animate-spin text-[#ec5b13] size-8 mb-3" />
                                        ) : faviconUrl ? (
                                            <div className="mb-3 size-10 flex items-center justify-center">
                                                <img src={faviconUrl} className="size-full object-contain" alt="Favicon" />
                                            </div>
                                        ) : (
                                            <span className="material-symbols-outlined text-3xl text-slate-500 group-hover:text-[#ec5b13] mb-3">branding_watermark</span>
                                        )}
                                        <span className="text-xs font-bold text-center text-slate-300">Favicon</span>
                                        <span className="text-[10px] text-slate-500 mt-1 uppercase">ICO, PNG (32x32px)</span>
                                    </div>
                                </div>
                            </section>

                            <hr className="border-[#2d2622]" />

                            {/* Section: Personnalisation du Ticket */}
                            <section className="space-y-6">
                                <div className="flex flex-col gap-1">
                                    <h2 className="text-xl font-bold text-white">Personnalisation du Ticket</h2>
                                    <p className="text-sm text-slate-400">Configurez l&apos;apparence des tickets imprimés en caisse.</p>

                                </div>
                                <div className="space-y-6 max-w-2xl">
                                    <div className="space-y-2">
                                        <label className="text-sm font-medium text-slate-400">Message de remerciement</label>
                                        <textarea
                                            className="w-full bg-[#1a1614] border border-[#2d2622] rounded-xl px-4 py-3 focus:ring-1 focus:ring-[#ec5b13] focus:border-transparent transition-all outline-none text-slate-100"
                                            rows={2}
                                            value={footerMessage}
                                            onChange={(e) => setFooterMessage(e.target.value)}
                                        />
                                    </div>
                                    <div className="flex items-center justify-between p-4 bg-[#1a1614] border border-[#2d2622] rounded-xl">
                                        <div className="flex flex-col gap-1">
                                            <span className="text-sm font-bold text-white">Afficher le logo sur le ticket</span>
                                            <span className="text-xs text-slate-500">Ajoute votre logo au sommet du ticket thermique</span>
                                        </div>
                                        <label className="custom-switch">
                                            <input
                                                type="checkbox"
                                                checked={showLogo}
                                                onChange={(e) => setShowLogo(e.target.checked)}
                                            />
                                            <span className="slider"></span>
                                        </label>
                                    </div>
                                </div>
                            </section>
                            <div className="pt-10 flex justify-end">
                                <button
                                    onClick={handleSave}
                                    disabled={isSaving}
                                    className="bg-[#ec5b13] hover:bg-orange-600 text-white px-8 py-4 rounded-xl font-bold text-base shadow-lg shadow-[#ec5b13]/40 transition-all flex items-center gap-3 disabled:opacity-50"
                                >
                                    {isSaving ? <Loader2 className="animate-spin size-5" /> : <Save className="size-5" />}
                                    {isSaving ? "Sauvegarde..." : "Sauvegarder les modifications"}
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            </main>

            <AddMemberModal isOpen={isOpen} onOpenChange={onOpenChange} />
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { Spinner } from "@heroui/react";
import { toast } from "react-hot-toast";
import { getPaidOrders, getFinishedOrders, processOrder, markOrderAsTermine } from "../caisse/actions";
import { ThermalReceipt } from "@/components/admin/receipt/ThermalReceipt";
import OrderDetailModal from "@/components/admin/modals/OrderDetailModal";
import { Eye } from "lucide-react";

export default function TraitementContent() {
    const [view, setView] = useState<"pending" | "finished">("pending");
    const [orders, setOrders] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [selectedOrder, setSelectedOrder] = useState<any | null>(null);
    const [codes, setCodes] = useState<Record<string, string>>({});
    const [isProcessing, setIsProcessing] = useState(false);
    const [searchTerm, setSearchTerm] = useState("");
    const [isDetailModalOpen, setIsDetailModalOpen] = useState(false);
    const [orderForDetail, setOrderForDetail] = useState<any | null>(null);
    const processedIds = React.useRef<Set<number>>(new Set());

    const loadOrders = async () => {
        setIsLoading(true);
        try {
            const data = view === "pending" ? await getPaidOrders() : await getFinishedOrders();
            setOrders(data);
        } catch (error) {
            console.error("Load failed:", error);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        loadOrders();
        const interval = setInterval(async () => {
            const data = view === "pending" ? await getPaidOrders() : await getFinishedOrders();
            setOrders(data);

            // Auto-Print Logic for Webhook-delivered orders
            if (view === "pending") {
                const orderToPrint = data.find((o: any) => o.status === "LIVRE" && !processedIds.current.has(o.id));
                if (orderToPrint) {
                    processedIds.current.add(orderToPrint.id);
                    toast.success(`Impression automatique : ${orderToPrint.orderNumber}`, { icon: '🖨️' });
                    setOrderForDetail(orderToPrint);
                    // The printing is now handled by a separate useEffect for reliability
                }
            }
        }, 10000);
        return () => clearInterval(interval);
    }, [view]);

    // Separate Effect for Auto-Print trigger
    useEffect(() => {
        if (orderForDetail && orderForDetail.status === "LIVRE") {
            const printTimer = setTimeout(async () => {
                console.log("Triggering window.print() for", orderForDetail.orderNumber);
                window.print();
                await markOrderAsTermine(orderForDetail.id);
                loadOrders();
            }, 800); // Increased delay for rendering safety
            return () => clearTimeout(printTimer);
        }
    }, [orderForDetail]);

    const handleCodeChange = (itemId: string, index: number, value: string) => {
        setCodes(prev => ({
            ...prev,
            [`${itemId}-${index}`]: value
        }));
    };

    const isOrderReady = () => {
        if (!selectedOrder) return false;
        return selectedOrder.items.every((item: any) => {
            for (let i = 0; i < item.quantity; i++) {
                if (!codes[`${item.id}-${i}`]) return false;
            }
            return true;
        });
    };

    const handleProcess = async () => {
        if (!selectedOrder || !isOrderReady()) return;
        setIsProcessing(true);
        try {
            const itemsWithCodes = selectedOrder.items.map((item: any) => ({
                id: item.id,
                name: item.name,
                codes: Array.from({ length: item.quantity }, (_, i) => codes[`${item.id}-${i}`])
            }));
            const res: any = await processOrder(selectedOrder.id, itemsWithCodes);
            if (res && !res.error) {
                // Flatten codes for the detail view / receipt
                const flattened = {
                    ...res,
                    items: (res.items as any[]).map(item => ({
                        ...item,
                        codes: (item.codes as any[]).map((c: any) => c.code)
                    }))
                };
                setOrderForDetail(flattened);
                loadOrders();
                setSelectedOrder(null);
                setCodes({});
                setTimeout(() => window.print(), 300);
            }
        } catch (error) {
            console.error("Process failed:", error);
        } finally {
            setIsProcessing(false);
        }
    };

    const filteredOrders = orders.filter(o =>
        o.orderNumber.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const getTimeAgo = (date: any) => {
        const diffMs = new Date().getTime() - new Date(date).getTime();
        const diffMins = Math.floor(diffMs / 60000);
        if (diffMins < 60) return `${diffMins} min`;
        return `${Math.floor(diffMins / 60)}h ${diffMins % 60}m`;
    };

    const getStatusBadge = (status: string) => {
        switch (status) {
            case "PAYE": return <span className="bg-emerald-500/20 text-emerald-400 text-[10px] font-bold uppercase px-2 py-0.5 rounded shrink-0">Payé</span>;
            case "PARTIEL": return <span className="bg-amber-500/20 text-amber-400 text-[10px] font-bold uppercase px-2 py-0.5 rounded shrink-0">Partiel</span>;
            case "NON_PAYE": return <span className="bg-red-500/20 text-red-500 text-[10px] font-bold uppercase px-2 py-0.5 rounded shrink-0">Dette</span>;
            case "TERMINE": return <span className="bg-blue-500/20 text-blue-400 text-[10px] font-bold uppercase px-2 py-0.5 rounded shrink-0">Livré</span>;
            default: return null;
        }
    };

    // Helper for category-based icons
    const getProductIcon = (name: string) => {
        const n = name.toLowerCase();
        if (n.includes('psn') || n.includes('playstation') || n.includes('xbox') || n.includes('game')) return 'sports_esports';
        if (n.includes('netflix') || n.includes('tv') || n.includes('streaming')) return 'tv_signin';
        return 'inventory_2';
    };

    return (
        <div className="flex h-[calc(100vh-64px)] w-full overflow-hidden bg-[#1a0f0a] mx-[-32px] my-[-32px] font-sans antialiased">
            <style jsx global>{`
                .custom-scrollbar::-webkit-scrollbar { width: 6px; }
                .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
                .custom-scrollbar::-webkit-scrollbar-thumb { background: #4b2e24; border-radius: 10px; }
            `}</style>

            <main className="flex-1 flex flex-col min-w-0 bg-[#1a0f0a]/95">
                {/* Header */}
                <header className="h-20 border-b border-[#ec5b13]/10 px-8 flex items-center justify-between shrink-0">
                    <div className="flex items-center gap-4">
                        <div className="size-10 bg-[#ec5b13]/10 rounded-xl flex items-center justify-center text-[#ec5b13]">
                            <span className="material-symbols-outlined font-light">history_edu</span>
                        </div>
                        <h2 className="text-xl font-bold tracking-tight">Traitement des Commandes (File d&apos;attente)</h2>
                    </div>
                    <div className="flex items-center gap-4">
                        <div className="relative w-64">
                            <span className="material-symbols-outlined absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 text-sm">search</span>
                            <input
                                className="w-full bg-[#2a1b15] border-none rounded-xl pl-10 pr-4 py-2 text-sm focus:ring-2 focus:ring-[#ec5b13]/50 text-slate-200 outline-none"
                                placeholder="Rechercher une commande..."
                                type="text"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                            />
                        </div>
                        <div className="flex gap-2 bg-[#2a1b15] p-1 rounded-xl">
                            <button
                                onClick={() => setView("pending")}
                                className={`px-4 py-1.5 text-xs font-bold rounded-lg transition-all ${view === "pending" ? "bg-[#ec5b13] text-white" : "text-slate-500 hover:text-white"}`}
                            >
                                Attente
                            </button>
                            <button
                                onClick={() => setView("finished")}
                                className={`px-4 py-1.5 text-xs font-bold rounded-lg transition-all ${view === "finished" ? "bg-[#ec5b13] text-white" : "text-slate-500 hover:text-white"}`}
                            >
                                Finies
                            </button>
                        </div>
                    </div>
                </header>

                {/* Dual Column Layout */}
                <div className="flex-1 flex overflow-hidden">
                    {/* Left Column: Queue */}
                    <section className="w-96 flex flex-col border-r border-[#ec5b13]/5 shrink-0">
                        <div className="p-6 shrink-0">
                            <h3 className="text-lg font-bold mb-1">File d'attente</h3>
                            <p className="text-sm text-slate-500 uppercase tracking-widest text-[10px] font-bold">
                                {view === "pending" ? "Payé - À Traiter" : "Traitement Terminé"}
                            </p>
                        </div>
                        <div className="flex-1 overflow-y-auto px-4 pb-6 space-y-3 custom-scrollbar">
                            {isLoading && orders.length === 0 ? (
                                <div className="flex justify-center p-12"><Spinner color="warning" /></div>
                            ) : filteredOrders.length === 0 ? (
                                <div className="text-center p-12 text-slate-600 italic">Aucune commande à traiter</div>
                            ) : filteredOrders.map(order => (
                                <div
                                    key={order.id}
                                    onClick={() => setSelectedOrder(order)}
                                    className={`p-4 rounded-2xl border transition-all cursor-pointer group ${selectedOrder?.id === order.id
                                        ? "bg-[#ec5b13]/10 border-[#ec5b13]/30 ring-1 ring-[#ec5b13]/20"
                                        : "bg-[#2a1b15]/40 border-white/5 hover:border-[#ec5b13]/20"}`}
                                >
                                    <div className="flex justify-between items-start mb-2 gap-2">
                                        <span className={`font-bold truncate ${selectedOrder?.id === order.id ? "text-[#ec5b13]" : "text-slate-300 group-hover:text-[#ec5b13]"}`}>
                                            #{order.orderNumber}
                                        </span>
                                        {getStatusBadge(order.status)}
                                    </div>
                                    <div className="space-y-1">
                                        <p className="text-sm text-slate-400">Il y a {getTimeAgo(order.createdAt)}</p>
                                        <div className="flex justify-between items-center">
                                            <p className="text-xs text-slate-500">
                                                {order.items.reduce((acc: number, item: any) => acc + item.quantity, 0)} articles • {Number(order.totalAmount).toLocaleString()} DZD
                                            </p>
                                            {order.status === "TERMINE" && (
                                                <button
                                                    onClick={(e) => {
                                                        e.stopPropagation();
                                                        setOrderForDetail(order);
                                                        setIsDetailModalOpen(true);
                                                    }}
                                                    className="p-1.5 rounded-lg bg-white/5 hover:bg-[#ec5b13]/20 text-slate-400 hover:text-[#ec5b13] transition-all"
                                                >
                                                    <Eye size={14} />
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </section>

                    {/* Right Column: Workspace */}
                    <section className="flex-1 flex flex-col min-w-0 bg-[#1a0f0a]/30 relative overflow-hidden">
                        {selectedOrder ? (
                            <div className="flex-1 flex flex-col min-w-0">
                                <div className="p-8 border-b border-white/5 shrink-0 flex justify-between items-center">
                                    <div>
                                        <h4 className="text-2xl font-bold tracking-tight mb-1">Détails de la Commande {selectedOrder.orderNumber}</h4>
                                        <p className="text-slate-500 text-sm flex items-center gap-2">
                                            <span className="material-symbols-outlined text-sm">calendar_today</span>
                                            {new Date(selectedOrder.createdAt).toLocaleDateString("fr-FR", { day: 'numeric', month: 'long', year: 'numeric' })} • {new Date(selectedOrder.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                        </p>
                                    </div>
                                    <div className="flex gap-2">
                                        <button
                                            onClick={() => window.print()}
                                            className="p-2.5 rounded-xl bg-[#2a1b15] border border-white/5 text-slate-400 hover:text-white transition-colors"
                                        >
                                            <span className="material-symbols-outlined">print</span>
                                        </button>
                                        <button className="p-2.5 rounded-xl bg-[#2a1b15] border border-white/5 text-slate-400 hover:text-red-400 transition-colors" onClick={() => setSelectedOrder(null)}>
                                            <span className="material-symbols-outlined">block</span>
                                        </button>
                                    </div>
                                </div>

                                <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
                                    {selectedOrder.items.map((item: any) => (
                                        <div key={item.id} className="space-y-4">
                                            <div className="flex justify-between items-center">
                                                <div className="flex items-center gap-4">
                                                    <div className={`size-14 rounded-2xl flex items-center justify-center border ${item.name.toLowerCase().includes('psn') ? 'bg-blue-600/20 text-blue-400 border-blue-600/30' : 'bg-red-600/20 text-red-500 border-red-600/30'}`}>
                                                        <span className="material-symbols-outlined text-3xl">{getProductIcon(item.name)}</span>
                                                    </div>
                                                    <div>
                                                        <h5 className="font-bold text-lg">{item.name}</h5>
                                                        <p className="text-slate-500 text-sm">Quantité: <span className="text-white font-medium">{item.quantity}</span></p>
                                                    </div>
                                                </div>
                                                <p className="text-xl font-bold whitespace-nowrap text-[#ec5b13]">{Number(item.price).toLocaleString()} DZD</p>
                                            </div>
                                            <div className="grid grid-cols-1 md:grid-cols-2 gap-3 pl-18">
                                                {Array.from({ length: item.quantity }).map((_, i) => (
                                                    <div key={i} className="relative">
                                                        <div className="absolute inset-y-0 left-0 w-1 bg-[#ec5b13]/40 rounded-full"></div>
                                                        <input
                                                            className="w-full bg-[#2a1b15] border-white/5 rounded-xl px-4 py-3 text-sm focus:ring-1 focus:ring-[#ec5b13] focus:border-[#ec5b13] outline-none text-white placeholder:text-slate-600 transition-all"
                                                            placeholder={`Entrez le code #${i + 1} pour ${item.name}...`}
                                                            type="text"
                                                            value={codes[`${item.id}-${i}`] || ""}
                                                            onChange={(e) => handleCodeChange(item.id, i, e.target.value)}
                                                            disabled={view === "finished"}
                                                        />
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    ))}

                                    <div className="mt-12 p-6 rounded-2xl bg-[#2a1b15]/30 border border-white/5 space-y-3">
                                        <div className="flex justify-between text-slate-400 text-sm">
                                            <span>Validation des codes</span>
                                            <span>{Object.keys(codes).length} injectés</span>
                                        </div>
                                        <div className="pt-3 border-t border-white/5 flex justify-between items-center text-white">
                                            <span className="font-bold text-lg">Total à valider</span>
                                            <span className="text-2xl font-black">{Number(selectedOrder.totalAmount).toLocaleString()} DZD</span>
                                        </div>
                                    </div>
                                </div>

                                {view === "pending" && (
                                    <footer className="p-8 border-t border-white/5 shrink-0 bg-[#1a0f0a]">
                                        <button
                                            onClick={handleProcess}
                                            disabled={!isOrderReady() || isProcessing}
                                            className={`w-full font-bold py-4 rounded-2xl shadow-xl transition-all flex items-center justify-center gap-3 active:scale-[0.98] ${isOrderReady() ? 'bg-gradient-to-r from-[#ec5b13] to-orange-600 text-white shadow-[#ec5b13]/20 hover:from-[#ec5b13] hover:to-[#ec5b13]' : 'bg-slate-800 text-slate-500 cursor-not-allowed'}`}
                                        >
                                            {isProcessing ? <Spinner size="sm" color="white" /> : (
                                                <>
                                                    <span className="material-symbols-outlined shrink-0">task_alt</span>
                                                    <span>Valider & Imprimer le Ticket</span>
                                                </>
                                            )}
                                        </button>
                                    </footer>
                                )}
                            </div>
                        ) : (
                            <div className="flex-1 flex flex-col items-center justify-center p-20 text-center group opacity-40">
                                <div className="size-48 rounded-[64px] bg-[#2a1b15]/40 border border-white/5 flex items-center justify-center mb-10 shadow-2xl relative overflow-hidden">
                                    <div className="absolute inset-0 bg-[#ec5b13]/5" />
                                    <span className="material-symbols-outlined text-8xl text-[#ec5b13]/20 group-hover:scale-110 transition-all duration-700">order_approve</span>
                                </div>
                                <h3 className="text-3xl font-bold text-slate-600 uppercase tracking-widest italic mb-4">Poste de Travail</h3>
                                <p className="text-slate-400 font-medium">Veuillez sélectionner une commande dans la file d&apos;attente</p>
                            </div>
                        )}
                    </section>
                </div>
            </main>

            {/* Hidden Print Container */}
            {(selectedOrder || orderForDetail) && (
                <div className="hidden print:block text-black">
                    <ThermalReceipt
                        orderNumber={selectedOrder?.orderNumber || orderForDetail?.orderNumber}
                        date={selectedOrder?.createdAt || orderForDetail?.createdAt}
                        items={(selectedOrder || orderForDetail)?.items.map((item: any) => ({
                            ...item,
                            codes: selectedOrder
                                ? Array.from({ length: item.quantity }, (_, i) => codes[`${item.id}-${i}`]).filter(Boolean)
                                : item.codes
                        })) || []}
                        totalAmount={selectedOrder?.totalAmount || orderForDetail?.totalAmount}
                    />
                </div>
            )}

            <OrderDetailModal
                isOpen={isDetailModalOpen}
                onClose={() => setIsDetailModalOpen(false)}
                order={orderForDetail}
                onReprint={() => {
                    setTimeout(() => window.print(), 200);
                }}
            />
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";

interface PlayerIdModalProps {
    isOpen: boolean;
    onClose: () => void;
    onConfirm: (id: string) => void;
    productName: string;
    productImage?: string;
}

export default function PlayerIdModal({
    isOpen,
    onClose,
    onConfirm,
    productName,
    productImage
}: PlayerIdModalProps) {
    const [playerId, setPlayerId] = useState("");
    const [isVisible, setIsVisible] = useState(false);

    useEffect(() => {
        if (isOpen) {
            setIsVisible(true);
            setPlayerId("");
        } else {
            const timer = setTimeout(() => setIsVisible(false), 300);
            return () => clearTimeout(timer);
        }
    }, [isOpen]);

    if (!isVisible && !isOpen) return null;

    const handleConfirm = () => {
        if (playerId.trim()) {
            onConfirm(playerId.trim());
            onClose();
        }
    };

    return (
        <section className={`fixed inset-0 z-[100] flex items-center justify-center bg-black/40 backdrop-blur-md transition-opacity duration-300 ${isOpen ? 'opacity-100' : 'opacity-0'}`} id="modal-overlay">
            {/* BEGIN: Product Info Modal Card */}
            <article className={`bg-white w-full max-w-xl shadow-2xl rounded-[32px] overflow-hidden mx-4 transition-all duration-400 ${isOpen ? 'translate-y-0 scale-100' : 'translate-y-10 scale-95'}`} data-purpose="modal-content-card">
                {/* Modal Content Padding */}
                <div className="p-8 md:p-10">
                    {/* BEGIN: Modal Header */}
                    <header className="flex flex-col items-center mb-8">
                        {/* Product Thumbnail */}
                        <div className="w-24 h-24 mb-6 bg-slate-50 border border-slate-100 rounded-2xl shadow-sm flex items-center justify-center overflow-hidden">
                            {productImage ? (
                                <img alt={productName} className="object-cover w-full h-full" src={productImage} />
                            ) : (
                                <div className="w-full h-full bg-slate-200 flex items-center justify-center">
                                    <span className="material-symbols-rounded text-slate-400 text-4xl">package</span>
                                </div>
                            )}
                        </div>
                        <h1 className="text-slate-900 text-3xl font-bold text-center leading-tight mb-2">
                            Informations requises
                        </h1>
                        <p className="text-slate-500 text-lg text-center max-w-sm">
                            Ce produit nécessite votre ID Joueur ou un lien pour être livré.
                        </p>
                        <p className="text-flexbox-orange font-bold mt-2 uppercase tracking-wide text-sm">{productName}</p>
                    </header>
                    {/* END: Modal Header */}

                    {/* BEGIN: Input Section */}
                    <section className="space-y-4" data-purpose="user-input-area">
                        <div>
                            <label className="block text-slate-700 font-semibold text-lg mb-3 ml-1" htmlFor="player-id">
                                Entrez votre Player ID / Identifiant
                            </label>
                            {/* Kiosk Optimized Input: High height, large font */}
                            <input
                                className="w-full h-16 px-6 text-2xl rounded-2xl border-2 border-slate-200 bg-slate-50 text-slate-900 placeholder:text-slate-300 focus:border-[#ec5b13] focus:ring-0 transition-colors duration-200 outline-none"
                                id="player-id"
                                name="player-id"
                                placeholder="Ex: 1234567890"
                                type="text"
                                value={playerId}
                                onChange={(e) => setPlayerId(e.target.value)}
                                autoFocus
                            />
                        </div>
                        {/* Visual Alert Box */}
                        <div className="flex items-start gap-3 p-4 bg-red-50 rounded-2xl border border-red-100" data-purpose="input-warning-notice">
                            <svg className="h-6 w-6 text-red-600 mt-0.5 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                                <path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2"></path>
                            </svg>
                            <p className="text-sm font-medium text-red-800 leading-snug">
                                Veuillez vérifier attentivement votre ID. Les erreurs de saisie ne sont pas remboursables.
                            </p>
                        </div>
                    </section>
                    {/* END: Input Section */}

                    {/* BEGIN: Modal Footer Actions */}
                    <footer className="grid grid-cols-2 gap-4 mt-10">
                        {/* Cancel Button */}
                        <button
                            className="h-16 rounded-2xl bg-slate-100 text-slate-600 font-bold text-lg active:scale-95 transition-transform duration-100 flex items-center justify-center"
                            data-purpose="action-cancel"
                            type="button"
                            onClick={onClose}
                        >
                            Annuler
                        </button>
                        {/* Submit Button */}
                        <button
                            className={`h-16 rounded-2xl bg-[#ec5b13] text-white font-bold text-lg shadow-lg shadow-orange-200 active:scale-95 transition-all duration-100 flex items-center justify-center disabled:opacity-50 disabled:grayscale`}
                            data-purpose="action-validate"
                            type="button"
                            onClick={handleConfirm}
                            disabled={!playerId.trim()}
                        >
                            Ajouter au panier
                        </button>
                    </footer>
                    {/* END: Modal Footer Actions */}
                </div>
            </article>
            {/* END: Product Info Modal Card */}
        </section>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import {
    Modal,
    ModalContent,
    ModalBody,
} from "@heroui/react";
import { useKioskStore } from "@/store/useKioskStore";
import PlayerIdModal from "./PlayerIdModal";

interface ProductModalProps {
    isOpen: boolean;
    onClose: () => void;
    product: any;
}

export default function ProductModal({ isOpen, onClose, product }: ProductModalProps) {
    const { addToCart } = useKioskStore();

    // State for local selection
    const [selectedVariant, setSelectedVariant] = useState<any>(null);
    const [quantity, setQuantity] = useState(1);
    const [isPlayerIdModalOpen, setIsPlayerIdModalOpen] = useState(false);

    // Reset selection when modal opens with a new product
    useEffect(() => {
        if (product && product.variants && product.variants.length > 0) {
            setSelectedVariant(product.variants[0]);
            setQuantity(1);
        }
    }, [product, isOpen]);

    if (!product) return null;

    const handleAddToCart = () => {
        if (!selectedVariant) return;

        if (product.requiresPlayerId) {
            setIsPlayerIdModalOpen(true);
            return;
        }

        finalizeAddToCart();
    };

    const finalizeAddToCart = (customData?: string) => {
        addToCart({
            variantId: selectedVariant.id,
            productId: product.id,
            name: selectedVariant.name,
            productName: product.name,
            price: selectedVariant.salePriceDzd,
            quantity: quantity,
            imageUrl: product.imageUrl,
            customData
        });
        onClose();
    };

    const incrementQuantity = () => setQuantity(prev => prev + 1);
    const decrementQuantity = () => setQuantity(prev => Math.max(1, prev - 1));

    const totalAmount = selectedVariant ? Number(selectedVariant.salePriceDzd) * quantity : 0;

    return (
        <Modal
            isOpen={isOpen}
            onOpenChange={onClose}
            size="4xl"
            placement="center"
            backdrop="blur"
            hideCloseButton
            classNames={{
                base: "bg-white rounded-[40px] shadow-2xl p-0 overflow-hidden",
                backdrop: "bg-slate-900/60 backdrop-blur-md",
                body: "p-0"
            }}
        >
            <ModalContent>
                <ModalBody className="relative flex flex-col p-0">
                    <style jsx global>{`
                        .material-symbols-outlined { font-size: 32px; }
                        .animate-in {
                            animation-duration: 300ms;
                            animation-fill-mode: both;
                        }
                    `}</style>

                    {/* Close Button */}
                    <button
                        onClick={onClose}
                        className="absolute top-8 right-8 size-16 bg-slate-100 hover:bg-slate-200 rounded-full flex items-center justify-center text-slate-900 transition-colors z-10"
                    >
                        <span className="material-symbols-outlined">close</span>
                    </button>

                    {/* Scrollable Content */}
                    <div className="p-10 lg:p-14 overflow-y-auto max-h-[85vh] no-scrollbar">
                        {/* 1. Header Section */}
                        <div className="flex flex-col md:flex-row gap-10 items-start md:items-center">
                            <div className="size-48 min-w-[192px] bg-slate-50 border border-slate-100 rounded-[32px] flex items-center justify-center overflow-hidden">
                                <img
                                    alt={product.name}
                                    className="w-2/3 object-contain"
                                    src={product.imageUrl}
                                />
                            </div>
                            <div className="flex-1">
                                <h1 className="text-slate-900 text-5xl font-extrabold leading-tight tracking-tight">{product.name}</h1>
                                <p className="text-slate-500 text-xl mt-4 leading-relaxed max-w-xl">
                                    {product.description || "Livraison instantanée du code d'activation sur votre ticket de caisse. Service Premium Digital."}
                                </p>
                            </div>
                        </div>

                        {/* 2. Variants Section */}
                        <div className="mt-12">
                            <h2 className="text-slate-900 text-2xl font-bold mb-6 flex items-center gap-3">
                                <span className="bg-[#ec5b13] text-white size-8 rounded-full flex items-center justify-center text-base">1</span>
                                Choisissez une option
                            </h2>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                {product.variants && product.variants.map((variant: any) => {
                                    const isActive = selectedVariant?.id === variant.id;
                                    return (
                                        <div
                                            key={variant.id}
                                            onClick={() => setSelectedVariant(variant)}
                                            className={`relative cursor-pointer rounded-[24px] p-8 flex flex-col justify-between min-h-[160px] transition-all border-4 ${isActive
                                                ? 'border-[#ec5b13] bg-orange-50'
                                                : 'border-slate-200 bg-white hover:bg-slate-50'
                                                }`}
                                        >
                                            {isActive && (
                                                <div className="absolute -top-4 -right-4 bg-[#ec5b13] text-white size-10 rounded-full flex items-center justify-center shadow-lg">
                                                    <span className="material-symbols-outlined !text-xl">check</span>
                                                </div>
                                            )}
                                            <div>
                                                <p className={`text-3xl font-bold ${isActive ? 'text-[#ec5b13]' : 'text-slate-900'}`}>{variant.name}</p>
                                                <p className={`text-2xl font-medium mt-1 ${isActive ? 'text-slate-900' : 'text-slate-500'}`}>
                                                    {Number(variant.salePriceDzd).toLocaleString()} DZD
                                                </p>
                                            </div>
                                            {isActive && (
                                                <div className="mt-2 inline-flex">
                                                    <span className="text-xs font-bold uppercase tracking-widest text-[#ec5b13]/70">Sélectionné</span>
                                                </div>
                                            )}
                                        </div>
                                    );
                                })}
                            </div>
                        </div>

                        {/* 3. Quantity Section */}
                        <div className="mt-12">
                            <h2 className="text-slate-900 text-2xl font-bold mb-6 flex items-center gap-3">
                                <span className="bg-[#ec5b13] text-white size-8 rounded-full flex items-center justify-center text-base">2</span>
                                Quantité
                            </h2>
                            <div className="bg-slate-50 rounded-full p-3 flex items-center justify-between max-w-sm mx-auto md:mx-0 shadow-inner border border-slate-200">
                                <button
                                    onClick={decrementQuantity}
                                    className="size-20 bg-white shadow-md rounded-full flex items-center justify-center hover:scale-105 active:scale-95 transition-transform"
                                >
                                    <span className="material-symbols-outlined text-slate-900">remove</span>
                                </button>
                                <span className="text-slate-900 text-5xl font-black px-8">{quantity}</span>
                                <button
                                    onClick={incrementQuantity}
                                    className="size-20 bg-white shadow-md rounded-full flex items-center justify-center hover:scale-105 active:scale-95 transition-transform"
                                >
                                    <span className="material-symbols-outlined text-slate-900">add</span>
                                </button>
                            </div>
                        </div>

                        {/* 4. Footer CTA Section */}
                        <div className="mt-16">
                            <button
                                onClick={handleAddToCart}
                                className="w-full h-32 bg-[#ec5b13] hover:bg-orange-600 text-white rounded-[40px] flex items-center justify-between px-10 shadow-xl shadow-orange-500/20 active:scale-[0.98] transition-all group"
                            >
                                <div className="flex items-center gap-6">
                                    <span className="material-symbols-outlined !text-5xl group-hover:translate-x-1 transition-transform">shopping_basket</span>
                                    <span className="text-4xl font-extrabold tracking-tight">Ajouter au panier</span>
                                </div>
                                <div className="h-16 w-px bg-white/20"></div>
                                <div className="text-right">
                                    <p className="text-white/80 text-lg font-bold uppercase tracking-widest">Total</p>
                                    <p className="text-4xl font-black">{totalAmount.toLocaleString()} DZD</p>
                                </div>
                            </button>
                            <p className="text-center text-slate-400 text-lg mt-6 font-medium">
                                Paiement sécurisé par carte ou espèces à la caisse.
                            </p>
                        </div>
                    </div>
                </ModalBody>
            </ModalContent>

            <PlayerIdModal
                isOpen={isPlayerIdModalOpen}
                onClose={() => setIsPlayerIdModalOpen(false)}
                onConfirm={(id) => finalizeAddToCart(id)}
                productName={product.name}
                productImage={product.imageUrl}
            />
        </Modal>
    );
}

"use client";

import React from "react";
import { useKioskStore } from "@/store/useKioskStore";
import { createKioskOrder } from "../actions";
import { useDisclosure } from "@heroui/react";
import DeliveryMethodModal from "../components/DeliveryMethodModal";

export default function CartView() {
    const {
        cart,
        setStep,
        clearCart,
        removeFromCart,
        updateQuantity,
        getTotalAmount,
        setLastOrderNumber
    } = useKioskStore();

    const { isOpen, onOpen, onOpenChange, onClose } = useDisclosure();
    const [isSubmitting, setIsSubmitting] = React.useState(false);

    const totalAmount = getTotalAmount();

    const handleUpdateQuantity = (variantId: number, delta: number, customData?: string) => {
        updateQuantity(variantId, delta, customData);
    };

    const handleCheckout = () => {
        if (cart.length === 0) return;
        onOpen();
    };

    const confirmOrder = async (deliveryMethod: "TICKET" | "WHATSAPP", phone?: string) => {
        setIsSubmitting(true);
        try {
            const formattedItems = cart.map(i => ({
                variantId: i.variantId,
                name: i.name,
                price: i.price,
                quantity: i.quantity,
                customData: i.customData
            }));
            const order = await createKioskOrder(formattedItems, totalAmount.toFixed(2), deliveryMethod, phone);
            setLastOrderNumber(order.orderNumber);
            setStep("CONFIRMATION");
            clearCart();
            onClose();
        } catch (error) {
            console.error("Order failed:", error);
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <div className="bg-[#F9FAFB] text-slate-900 font-sans flex flex-col h-screen overflow-hidden select-none">
            <style jsx global>{`
                .custom-scrollbar::-webkit-scrollbar {
                    width: 12px;
                }
                .custom-scrollbar::-webkit-scrollbar-track {
                    background: transparent;
                }
                .custom-scrollbar::-webkit-scrollbar-thumb {
                    background: #e2e8f0;
                    border-radius: 10px;
                }
                .shadow-up {
                    box-shadow: 0 -10px 25px -5px rgba(0, 0, 0, 0.1), 0 -8px 10px -6px rgba(0, 0, 0, 0.1);
                }
            `}</style>

            {/* BEGIN: MainHeader */}
            <header className="flex items-center justify-between px-8 py-10 bg-[#F9FAFB] z-10 shrink-0">
                {/* Back Button */}
                <button
                    onClick={() => setStep("CATALOGUE")}
                    aria-label="Retour"
                    className="w-20 h-20 bg-white rounded-full flex items-center justify-center shadow-md active:scale-95 transition-transform"
                >
                    <svg className="w-10 h-10" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24">
                        <path d="M10.5 19.5L3 12m0 0l7.5-7.5M3 12h18" strokeLinecap="round" strokeLinejoin="round"></path>
                    </svg>
                </button>
                {/* Title */}
                <h1 className="text-4xl font-bold tracking-tight">Mon Panier</h1>
                {/* Empty Cart Button */}
                <button
                    onClick={clearCart}
                    className="px-6 py-4 text-xl font-semibold text-red-500 active:bg-red-50 rounded-2xl transition-colors"
                >
                    Vider le panier
                </button>
            </header>
            {/* END: MainHeader */}

            {/* BEGIN: CartContent */}
            <main className="flex-1 overflow-y-auto px-8 pb-48 custom-scrollbar">
                <div className="flex flex-col gap-6 max-w-5xl mx-auto py-4">
                    {cart.length === 0 ? (
                        <div className="flex flex-col items-center justify-center py-20 text-slate-300">
                            <svg className="w-32 h-32 mb-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z"></path>
                            </svg>
                            <p className="text-3xl font-bold">Votre panier est vide</p>
                            <button
                                onClick={() => setStep("CATALOGUE")}
                                className="mt-8 px-10 py-5 bg-white border border-slate-200 rounded-full text-slate-600 text-xl font-bold shadow-sm active:scale-95 transition-all"
                            >
                                Retour au catalogue
                            </button>
                        </div>
                    ) : cart.map((item) => (
                        <div key={`${item.variantId}-${item.customData || 'no-data'}`} className="bg-white rounded-[32px] p-6 shadow-sm flex items-center gap-6">
                            {/* Product Image */}
                            <div className="w-32 h-32 bg-slate-50 border border-slate-100 rounded-2xl flex items-center justify-center flex-shrink-0 overflow-hidden">
                                {item.imageUrl ? (
                                    <img
                                        src={item.imageUrl}
                                        alt={item.productName}
                                        className="w-2/3 h-2/3 object-contain"
                                    />
                                ) : (
                                    <svg className="w-16 h-16 text-slate-300" fill="currentColor" viewBox="0 0 24 24">
                                        <path d="M12 2C6.477 2 2 6.477 2 12s4.477 10 10 10 10-4.477 10-10S17.523 2 12 2zm0 18c-4.411 0-8-3.589-8-8s3.589-8 8-8 8 3.589 8 8-3.589 8-8 8z"></path>
                                    </svg>
                                )}
                            </div>
                            {/* Product Details */}
                            <div className="flex-1">
                                <h2 className="text-2xl font-bold">{item.productName}</h2>
                                <p className="text-xl text-slate-500 mt-1">{item.name}</p>
                                {item.customData && (
                                    <div className="mt-2 inline-flex items-center gap-2 bg-[#ec5b13]/5 text-[#ec5b13] px-4 py-1.5 rounded-xl border border-[#ec5b13]/10">
                                        <span className="material-symbols-outlined !text-lg text-[#ec5b13]">poker_chip</span>
                                        <span className="text-sm font-bold uppercase tracking-wider">ID: {item.customData}</span>
                                    </div>
