                                    onClick={() => handleUpdateQuantity(item.variantId, -1, item.customData)}
                                    className="w-16 h-16 flex items-center justify-center text-3xl font-bold text-slate-600 active:bg-white rounded-full transition-colors"
                                >
                                    -
                                </button>
                                <span className="w-16 text-center text-3xl font-bold">{item.quantity}</span>
                                <button
                                    onClick={() => handleUpdateQuantity(item.variantId, 1, item.customData)}
                                    className="w-16 h-16 flex items-center justify-center text-3xl font-bold text-slate-600 active:bg-white rounded-full transition-colors"
                                >
                                    +
