"use client";

import React, { useState, useEffect, useTransition } from "react";
import { useRouter, usePathname, useSearchParams } from "next/navigation";
import NextImage from "next/image";
import {
    Button,
    Card,
    CardBody,
    Input,
    Table,
    TableHeader,
    TableColumn,
    TableBody,
    TableRow,
    TableCell,
    Chip,
    Select,
    SelectItem,
    User as HeroUser,
    Dropdown,
    DropdownTrigger,
    DropdownMenu,
    DropdownItem,
    Spinner
} from "@heroui/react";
import {
    MoreVertical,
    Plus,
    Search,
    Bell,
    Settings,
    LayoutGrid,
    Package,
    Wallet,
    Truck,
    AlertTriangle,
    PlusCircle,
    ArrowUpCircle,
    Landmark,
    CircleDollarSign,
    Download,
    Printer,
    Filter,
    Edit,
    Trash
} from "lucide-react";
import { AddProductModal } from "@/components/admin/modals/AddProductModal";
import { AddCategoryModal } from "@/components/admin/modals/AddCategoryModal";
import { ManageCategoriesModal } from "@/components/admin/modals/ManageCategoriesModal";
import { RechargeBalanceModal } from "@/components/admin/modals/RechargeBalanceModal";
import { deleteProductAction } from "@/app/admin/catalogue/actions";
import toast from "react-hot-toast";
import Link from "next/link";

interface Product {
    id: number;
    name: string;
    description: string | null;
    imageUrl: string | null;
    categoryId: number | null;
    variants: any[];
}

interface Supplier {
    id: number;
    name: string;
    balanceDzd: string | null;
    balanceUsd: string | null;
    exchangeRate: string | null;
    baseCurrency: string | null;
}

interface Category {
    id: number;
    name: string;
    icon: string | null;
    imageUrl: string | null;
}

interface CatalogueContentProps {
    initialProducts: Product[];
    suppliers: Supplier[];
    categories: Category[];
    initialTotal: number;
    initialTotalPages: number;
    initialPage: number;
    initialSearch: string;
    initialCategoryId: string;
}

export default function CatalogueContent({
    initialProducts,
    suppliers,
    categories,
    initialTotal,
    initialTotalPages,
    initialPage,
    initialSearch,
    initialCategoryId
}: CatalogueContentProps) {
    const router = useRouter();
    const pathname = usePathname();
    const searchParams = useSearchParams();
    const [isPending, startTransition] = useTransition();

    const [isAddProductOpen, setIsAddProductOpen] = useState(false);
    const [productToEdit, setProductToEdit] = useState<Product | null>(null);
    const [isAddCategoryOpen, setIsAddCategoryOpen] = useState(false);
    const [isManageCategoriesOpen, setIsManageCategoriesOpen] = useState(false);
    const [categoryToEdit, setCategoryToEdit] = useState<Category | null>(null);
    const [selectedSupplier, setSelectedSupplier] = useState<Supplier | null>(null);
    const [isRechargeOpen, setIsRechargeOpen] = useState(false);

    // Filter states synced with URL
    const [searchTerm, setSearchTerm] = useState(initialSearch);
    const [selectedCategoryId, setSelectedCategoryId] = useState(initialCategoryId);

    const updateParams = (newParams: Record<string, string | number | null>) => {
        const params = new URLSearchParams(searchParams.toString());
        Object.entries(newParams).forEach(([key, value]) => {
            if (value === null || value === "all" || value === "") {
                params.delete(key);
            } else {
                params.set(key, value.toString());
            }
        });
        // Always reset to page 1 on search/category change unless page is explicitly provided
        if (!newParams.page) params.delete("page");

        startTransition(() => {
            router.push(`${pathname}?${params.toString()}`);
        });
    };

    // Debounced search
    useEffect(() => {
        if (searchTerm === initialSearch) return;
        const handler = setTimeout(() => {
            updateParams({ search: searchTerm });
        }, 500);
        return () => clearTimeout(handler);
    }, [searchTerm]);

    const handlePageChange = (newPage: number) => {
        updateParams({ page: newPage });
    };

    const handleCategoryChange = (val: string) => {
        setSelectedCategoryId(val);
        updateParams({ categoryId: val });
    };

    const handleOpenRecharge = (supplier: Supplier) => {
        setSelectedSupplier(supplier);
        setIsRechargeOpen(true);
    };

    const handleEditCategory = (category: Category) => {
        setCategoryToEdit(category);
        setIsManageCategoriesOpen(false);
        setIsAddCategoryOpen(true);
    };

    const handleCloseAddCategory = () => {
        setIsAddCategoryOpen(false);
        setCategoryToEdit(null);
    };

    const handleEditProduct = (product: Product) => {
        setProductToEdit(product);
        setIsAddProductOpen(true);
    };

    const handleCloseAddProduct = () => {
        setIsAddProductOpen(false);
        setProductToEdit(null);
    };

    const handleDeleteProduct = async (id: number) => {
        if (!confirm("Êtes-vous sûr de vouloir supprimer ce produit ? Cette action est irréversible et supprimera toutes les variantes associées.")) {
            return;
        }

        const res = await deleteProductAction(id);
        if (res.success) {
            toast.success("Produit supprimé");
        } else {
            toast.error(res.error || "Échec de la suppression");
        }
    };

    const products = initialProducts;
    const filteredProductsForCount = initialProducts; // This replaces the local filter for stats

    const handleExportCSV = () => {
        const headers = ["ID", "Nom", "Catégorie", "Prix Min", "Profit Moyen"];
        const rows = products.map(p => {
            const cat = categories.find(c => c.id === p.categoryId);
            const minPrice = p.variants.length > 0
                ? Math.min(...p.variants.map(v => Number(v.salePriceDzd)))
                : 0;
            return [
                p.id,
                p.name,
                cat?.name || "Sans catégorie",
                minPrice,
                "Profit Estimé"
            ];
        });

        const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.setAttribute("href", url);
        link.setAttribute("download", `catalogue_${new Date().toISOString()}.csv`);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        toast.success("Catalogue exporté");
    };

    const handlePrint = () => {
        window.print();
    };

    const totalPages = initialTotalPages;
    const paginatedProducts = products;

    return (
        <div className="flex flex-col min-h-full space-y-8 bg-[#0a0a0a]">
            {/* Header */}
            <header className="flex items-center justify-between">
                <h2 className="text-xl font-bold text-white tracking-tight">Catalogue & Fournisseurs</h2>
                <div className="flex items-center gap-4">
                    <div className="relative w-64">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 w-4 h-4 shrink-0" />
                        <Input
                            classNames={{
                                input: "pl-10 text-white",
                                inputWrapper: "bg-[#161616] border border-[#262626] rounded-xl h-10 text-sm focus-within:ring-2 focus-within:ring-primary/50"
                            }}
                            placeholder="Rechercher..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                    <Select
                        className="w-48"
                        classNames={{
                            trigger: "bg-[#161616] border border-[#262626] rounded-xl h-10 min-h-10",
                            value: "text-white text-sm"
                        }}
                        placeholder="Catégorie"
                        selectedKeys={[selectedCategoryId]}
                        onSelectionChange={(keys) => handleCategoryChange(Array.from(keys)[0] as string)}
                    >
                        {[
                            { id: "all", name: "Toutes les catégories" },
                            ...categories.map(c => ({ id: c.id.toString(), name: c.name }))
                        ].map((cat) => (
                            <SelectItem key={cat.id} textValue={cat.name}>
                                {cat.name}
                            </SelectItem>
                        ))}
                    </Select>
                    {isPending && <Spinner size="sm" color="warning" className="shrink-0" />}
                    <div className="flex gap-2 border-l border-[#262626] pl-4">
                        <Button
                            isIconOnly
                            className="size-10 rounded-xl bg-[#161616] border border-[#262626] flex items-center justify-center hover:bg-[#262626] transition-colors"
                            onClick={handleExportCSV}
                        >
                            <Download className="w-5 h-5 text-slate-400 shrink-0" />
                        </Button>
                    </div>
                    <Button
                        isIconOnly
                        className="size-10 rounded-xl bg-[#161616] border border-[#262626] flex items-center justify-center hover:bg-[#262626] transition-colors"
                        onClick={() => toast.success("Aucune nouvelle notification")}
                    >
                        <Bell className="w-5 h-5 text-slate-400 shrink-0" />
                    </Button>
                    <Button
                        isIconOnly
                        className="size-10 rounded-xl bg-[#161616] border border-[#262626] flex items-center justify-center hover:bg-[#262626] transition-colors"
                        as={Link}
                        href="/admin/settings"
                    >
                        <Settings className="w-5 h-5 text-slate-400 shrink-0" />
                    </Button>
                </div>
            </header>

            {/* Section 1: Portefeuilles Fournisseurs */}
            <section>
                <div className="flex items-center justify-between mb-6">
                    <h3 className="text-lg font-bold flex items-center gap-2 text-white">
                        <Landmark className="text-primary w-5 h-5 shrink-0" />
                        Portefeuilles Fournisseurs
                    </h3>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                    {suppliers.map((supplier) => {
                        const balanceDzd = parseFloat(supplier.balanceDzd || "0");
                        const isLowBalance = balanceDzd < 5000;
                        return (
                            <div key={supplier.id} className={`bg-[#161616] p-5 rounded-xl border ${isLowBalance ? 'border-red-500/50' : 'border-[#262626]'} shadow-sm flex flex-col justify-between h-44 relative overflow-hidden group hover:border-primary/30 transition-colors`}>
                                {isLowBalance && (
                                    <div className="absolute top-0 right-0 p-2">
                                        <span className="flex items-center gap-1 px-2 py-1 bg-red-500/10 text-red-500 text-[10px] font-bold rounded-full uppercase shrink-0">
                                            <AlertTriangle className="w-3 h-3 shrink-0" />
                                            Alerte Solde
                                        </span>
                                    </div>
                                )}
                                <div className="flex justify-between items-start">
                                    <div>
                                        <p className="text-sm text-slate-500 font-medium uppercase tracking-wider">{supplier.name}</p>
                                        <h4 className={`text-2xl font-black mt-2 leading-none tracking-tighter ${isLowBalance ? 'text-red-500' : 'text-white'}`}>
                                            {balanceDzd.toLocaleString()} <span className="text-sm font-bold text-slate-500">DZD</span>
                                        </h4>
                                        <p className="text-xs text-slate-600 mt-2 font-bold uppercase">{parseFloat(supplier.balanceUsd || "0").toLocaleString()} USD</p>
                                    </div>
                                    <div className="p-2 bg-primary/10 rounded-lg text-primary shrink-0 transition-transform group-hover:scale-110">
                                        {parseFloat(supplier.balanceUsd || "0") > 0 ? <CircleDollarSign className="w-4 h-4 shrink-0" /> : <Landmark className="w-4 h-4 shrink-0" />}
                                    </div>
                                </div>
                                <Button
                                    size="sm"
                                    onClick={() => handleOpenRecharge(supplier)}
                                    className={`w-full font-bold ${isLowBalance ? 'bg-red-500 text-white' : 'bg-primary/10 text-primary hover:bg-primary hover:text-white'} transition-all rounded-lg`}
                                    startContent={isLowBalance ? <ArrowUpCircle className="w-4 h-4 shrink-0" /> : <PlusCircle className="w-4 h-4 shrink-0" />}
                                >
                                    {isLowBalance ? 'Recharger Urgent' : 'Recharger'}
                                </Button>
                            </div>
                        );
                    })}
                </div>
            </section>

            {/* Section 2: Catalogue Produits */}
            <section>
                <div className="flex items-center justify-between mb-6">
                    <h3 className="text-lg font-bold flex items-center gap-2 text-white">
                        <Package className="text-primary w-5 h-5 shrink-0" />
                        Catalogue Produits
                    </h3>
                    <div className="flex gap-3">
                        <Button
                            onPress={() => setIsManageCategoriesOpen(true)}
                            variant="flat"
                            className="flex items-center gap-2 px-6 py-2.5 bg-[#ec5b13]/10 text-[#ec5b13] rounded-xl text-sm font-black hover:bg-[#ec5b13]/20 transition-all active:scale-95"
                            startContent={<Settings className="w-5 h-5 shrink-0" />}
                        >
                            Gérer les Catégories
                        </Button>
                        <Button
                            onPress={() => setIsAddProductOpen(true)}
                            className="flex items-center gap-2 px-6 py-2.5 bg-primary text-white rounded-xl text-sm font-black shadow-lg shadow-primary/20 hover:scale-[1.02] transition-transform active:scale-95"
                            startContent={<Plus className="w-5 h-5 shrink-0" />}
                        >
                            Ajouter un Produit
                        </Button>
                    </div>
                </div>

                <div className="bg-[#161616] border border-[#262626] rounded-2xl overflow-hidden shadow-sm">
                    <div className="overflow-x-auto">
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr className="bg-[#262626]/50 border-b border-[#262626]">
                                    <th className="px-6 py-4 text-[10px] font-black uppercase tracking-widest text-slate-500">Produit</th>
                                    <th className="px-6 py-4 text-[10px] font-black uppercase tracking-widest text-slate-500">Catégorie</th>
                                    <th className="px-6 py-4 text-[10px] font-black uppercase tracking-widest text-slate-500 text-right">Prix de Vente</th>
                                    <th className="px-6 py-4 text-[10px] font-black uppercase tracking-widest text-slate-500 text-right">Profit Est.</th>
                                    <th className="px-6 py-4 text-[10px] font-black uppercase tracking-widest text-slate-500 text-center">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-[#262626]">
                                {paginatedProducts.map((product) => {
                                    const category = categories.find(c => c.id === product.categoryId);
                                    const minPrice = product.variants.length > 0
                                        ? Math.min(...product.variants.map(v => Number(v.salePriceDzd)))
                                        : 0;

                                    // Improved profit calculation across variants for display
                                    const avgProfit = product.variants.length > 0
                                        ? product.variants.reduce((acc, v) => {
                                            const sellPrice = parseFloat(v.salePriceDzd);

                                            // Find the primary linked supplier for this variant
                                            const linkedSup = v.variantSuppliers?.[0];
                                            let buyPriceUsd = parseFloat(v.purchasePriceUsd);
                                            let rate = 225;

                                            if (linkedSup) {
                                                buyPriceUsd = parseFloat(linkedSup.purchasePriceUsd);
                                                // Find the supplier object to get their specific rate
                                                const supplierObj = suppliers.find(s => s.id === linkedSup.supplierId);
                                                if (supplierObj) {
                                                    rate = parseFloat(supplierObj.exchangeRate || "225");
                                                }
                                            } else if (suppliers.length > 0) {
                                                // Fallback to first supplier rate
                                                rate = parseFloat(suppliers[0].exchangeRate || "225");
                                            }

                                            return acc + (sellPrice - (buyPriceUsd * rate));
                                        }, 0) / product.variants.length
                                        : 0;

                                    return (
                                        <tr key={product.id} className="hover:bg-white/5 transition-colors group">
                                            <td className="px-6 py-4">
                                                <div className="flex items-center gap-3">
                                                    <div className="size-12 rounded-xl bg-[#262626] flex items-center justify-center shrink-0 overflow-hidden border border-white/5">
                                                        {product.imageUrl ? (
                                                            <NextImage src={product.imageUrl} alt={product.name} width={48} height={48} className="w-full h-full object-cover shrink-0" />
                                                        ) : (
                                                            <Package className="w-6 h-6 text-primary shrink-0 opacity-50" />
                                                        )}
                                                    </div>
                                                    <div className="min-w-0">
                                                        <p className="text-sm font-bold text-white truncate uppercase tracking-tight">{product.name}</p>
                                                        <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">ID: #{product.id + 1000}</p>
                                                    </div>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4">
                                                <Chip size="sm" variant="flat" className="font-bold text-[10px] uppercase bg-[#262626] text-slate-400 border border-white/5">
                                                    {category?.name || "Sans catégorie"}
                                                </Chip>
                                            </td>
                                            <td className="px-6 py-4 text-right">
                                                <p className="text-sm font-black text-white whitespace-nowrap">{minPrice.toLocaleString()} <span className="text-[10px] text-slate-500">DZD</span></p>
                                            </td>
                                            <td className="px-6 py-4 text-right">
                                                <p className={`text-sm font-black whitespace-nowrap ${avgProfit > 0 ? 'text-green-500' : 'text-red-500'}`}>
                                                    {avgProfit > 0 ? '+' : ''}{Math.round(avgProfit).toLocaleString()} <span className="text-[10px] opacity-60">DZD</span>
                                                </p>
                                            </td>
                                            <td className="px-6 py-4 text-center">
                                                <Dropdown classNames={{ content: "bg-[#161616] border border-[#262626]" }}>
                                                    <DropdownTrigger>
                                                        <Button
                                                            isIconOnly
                                                            size="sm"
                                                            variant="light"
                                                            className="text-slate-500 hover:text-white transition-colors hover:bg-[#262626]"
                                                        >
                                                            <MoreVertical className="w-4 h-4 shrink-0" />
                                                        </Button>
                                                    </DropdownTrigger>
                                                    <DropdownMenu aria-label="Actions produit">
                                                        <DropdownItem
                                                            key="edit"
                                                            startContent={<Edit className="w-4 h-4 shrink-0 text-primary" />}
                                                            className="text-white hover:bg-white/5"
                                                            onPress={() => handleEditProduct(product)}
                                                        >
                                                            Modifier
                                                        </DropdownItem>
                                                        <DropdownItem
                                                            key="delete"
                                                            className="text-red-500 hover:bg-red-500/10"
                                                            startContent={<Trash className="w-4 h-4 shrink-0" />}
                                                            onPress={() => handleDeleteProduct(product.id)}
                                                        >
                                                            Supprimer
                                                        </DropdownItem>
                                                    </DropdownMenu>
                                                </Dropdown>
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                    <div className="px-6 py-4 border-t border-[#262626] bg-[#262626]/20 flex items-center justify-between">
                        <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">
                            Page {initialPage} sur {totalPages || 1} ({initialTotal} produits au total)
                        </p>
                        <div className="flex gap-2">
                            <Button
                                size="sm"
                                variant="flat"
                                className="bg-[#262626] text-white font-bold h-8 px-4 rounded-lg disabled:opacity-50"
                                onClick={() => handlePageChange(Math.max(1, initialPage - 1))}
                                disabled={initialPage === 1 || isPending}
                            >
                                Précédent
                            </Button>
                            <Button
                                size="sm"
                                variant="flat"
                                className="bg-[#262626] text-white font-bold h-8 px-4 rounded-lg disabled:opacity-50"
                                onClick={() => handlePageChange(Math.min(totalPages, initialPage + 1))}
                                disabled={initialPage >= totalPages || isPending}
                            >
                                Suivant
                            </Button>
                        </div>
                    </div>
                </div>
            </section>

            <AddProductModal
                isOpen={isAddProductOpen}
                onClose={handleCloseAddProduct}
                categories={categories}
                suppliers={suppliers}
                productToEdit={productToEdit}
            />

            <AddCategoryModal
                isOpen={isAddCategoryOpen}
                onClose={handleCloseAddCategory}
                categoryToEdit={categoryToEdit}
            />

            <ManageCategoriesModal
                isOpen={isManageCategoriesOpen}
                onClose={() => setIsManageCategoriesOpen(false)}
                categories={categories}
                onEdit={handleEditCategory}
            />

            {selectedSupplier && (
                <RechargeBalanceModal
                    isOpen={isRechargeOpen}
                    onClose={() => {
                        setIsRechargeOpen(false);
                        setSelectedSupplier(null);
                    }}
                    supplierId={selectedSupplier.id}
                    supplierName={selectedSupplier.name}
                    currentBalance={selectedSupplier.balanceUsd || "0"}
                    exchangeRate={selectedSupplier.exchangeRate || "225"}
                />
            )}
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { Lock, Delete, ArrowRight, User as UserIcon } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { useAuthStore } from "@/store/useAuthStore";
import { verifyPinAction } from "@/app/admin/login/actions";

export const LockScreen = () => {
    const [pin, setPin] = useState("");
    const [error, setError] = useState(false);
    const [isLocked, setIsLocked] = useState(true);

    const user = useAuthStore((state) => state.user);

    const handleNumberClick = (num: string) => {
        if (pin.length < 4) {
            setPin(prev => prev + num);
            setError(false);
        }
    };

    const handleDelete = () => {
        setPin(prev => prev.slice(0, -1));
        setError(false);
    };

    useEffect(() => {
        const verifyPin = async () => {
            if (pin.length === 4) {
                const result = await verifyPinAction(pin);
                if (result.success) {
                    setIsLocked(false);
                } else {
                    setError(true);
                    setTimeout(() => setPin(""), 500);
                }
            }
        };
        verifyPin();
    }, [pin]);

    if (!isLocked) return null;

    return (
        <AnimatePresence>
            <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0, scale: 1.1 }}
                className="fixed inset-0 z-[9999] bg-[#0a0a0a]/95 backdrop-blur-xl flex flex-col items-center justify-center p-4 select-none"
            >
                {/* Header Profile */}
                <div className="flex flex-col items-center mb-12">
                    <div className="w-24 h-24 rounded-full bg-[#161616] border border-[#262626] flex items-center justify-center mb-4 relative">
                        <div className="w-20 h-20 rounded-full overflow-hidden bg-gradient-to-tr from-[#ec5b13]/20 to-transparent flex items-center justify-center">
                            <img
                                src="https://lh3.googleusercontent.com/aida-public/AB6AXuCZzSogzgSYWL4sV8cYS-i9sYM5fwva6Q0n4I55293IQmD03umRiums_O9xTBdasBU1_angHiWiAckgyWwn6UB9MBLipWMhFehIUd_Qc0NUCfkXrUB7xtX-66jetAhnxQNxVTRztumuzjGfV4latkz0g53wc7eiJUn89bYwLuPezAenuEtVe-t4k1298Xg1AQqPP6l314oAlSj3m3UMutiTNXAv4ywmJUO7cWO3xprkiMgliBjEdbhP9gqPQREeem3Jv00wZuEZHdbM"
                                alt="Admin"
                                className="w-full h-full object-cover opacity-80"
                            />
                        </div>
                        <div className="absolute -bottom-1 -right-1 bg-[#ec5b13] p-1.5 rounded-full shadow-lg">
                            <Lock className="w-3 h-3 text-white" />
                        </div>
                    </div>
                    <h2 className="text-xl font-bold text-white tracking-tight">{user?.nom || "Administrateur"}</h2>
                    <p className="text-slate-500 text-sm mt-1">Session verrouillée</p>
                </div>

                {/* PIN Display */}
                <div className="flex gap-4 mb-12">
                    {[0, 1, 2, 3].map((i) => (
                        <div
                            key={i}
                            className={`w-4 h-4 rounded-full border-2 transition-all duration-200 ${pin[i]
                                ? "bg-[#ec5b13] border-[#ec5b13] scale-110 shadow-[0_0_15px_rgba(236,91,19,0.5)]"
                                : "border-[#262626]"
                                } ${error ? "animate-shake bg-red-500 border-red-500" : ""}`}
                        />
                    ))}
                </div>

                {/* Keypad */}
                <div className="grid grid-cols-3 gap-6 max-w-xs w-full">
                    {["1", "2", "3", "4", "5", "6", "7", "8", "9"].map((num) => (
                        <button
                            key={num}
                            onClick={() => handleNumberClick(num)}
                            className="w-20 h-20 rounded-full bg-[#161616] border border-[#262626] text-2xl font-bold text-white hover:bg-[#262626] active:scale-90 transition-all flex items-center justify-center outline-none"
                        >
                            {num}
                        </button>
                    ))}
                    <div /> {/* Empty space */}
                    <button
                        onClick={() => handleNumberClick("0")}
                        className="w-20 h-20 rounded-full bg-[#161616] border border-[#262626] text-2xl font-bold text-white hover:bg-[#262626] active:scale-90 transition-all flex items-center justify-center outline-none"
                    >
                        0
                    </button>
                    <button
                        onClick={handleDelete}
                        className="w-20 h-20 rounded-full flex items-center justify-center text-slate-400 hover:text-white active:scale-90 transition-all outline-none"
                    >
                        <Delete className="w-8 h-8" />
                    </button>
                </div>

                {/* Bottom Action */}
                <button
                    onClick={() => window.location.href = "/admin/login"}
                    className="mt-12 text-slate-500 hover:text-[#ec5b13] text-sm font-medium transition-colors flex items-center gap-2"
                >
                    Changer de compte <ArrowRight className="w-4 h-4" />
                </button>

                <style jsx>{`
                    @keyframes shake {
                        0%, 100% { transform: translateX(0); }
                        25% { transform: translateX(-5px); }
                        75% { transform: translateX(5px); }
                    }
                    .animate-shake {
                        animation: shake 0.2s ease-in-out infinite;
                    }
                `}</style>
            </motion.div>
        </AnimatePresence>
    );
};

"use client";

import React, { useState, useRef } from "react";
import {
    Modal,
    ModalContent,
    ModalHeader,
    ModalBody,
    ModalFooter,
    Button
} from "@heroui/react";
import { uploadImage } from "@/app/admin/actions/upload";
import { createCategoryAction, updateCategoryAction } from "@/app/admin/catalogue/actions";
import { toast } from "react-hot-toast";

interface AddCategoryModalProps {
    isOpen: boolean;
    onClose: () => void;
    categoryToEdit?: {
        id: number;
        name: string;
        imageUrl: string | null;
    } | null;
}

export const AddCategoryModal = ({ isOpen, onClose, categoryToEdit }: AddCategoryModalProps) => {
    const [isSaving, setIsSaving] = useState(false);
    const [name, setName] = useState("");
    const [selectedFile, setSelectedFile] = useState<File | null>(null);
    const [previewUrl, setPreviewUrl] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Initialize state when modal opens or categoryToEdit changes
    React.useEffect(() => {
        if (categoryToEdit) {
            setName(categoryToEdit.name);
            setPreviewUrl(categoryToEdit.imageUrl);
            setSelectedFile(null);
        } else {
            resetForm();
        }
    }, [categoryToEdit, isOpen]);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            setSelectedFile(file);
            const url = URL.createObjectURL(file);
            setPreviewUrl(url);
        }
    };

    const handleSubmit = async () => {
        if (!name) {
            toast.error("Veuillez saisir un nom pour la catégorie");
            return;
        }

        setIsSaving(true);
        let imageUrl: string | null = categoryToEdit?.imageUrl || null;

        try {
            if (selectedFile) {
                const formData = new FormData();
                formData.append("file", selectedFile);
                const uploadRes = await uploadImage(formData);
                if (uploadRes.success && uploadRes.url) {
                    imageUrl = uploadRes.url;
                } else {
                    toast.error("Échec de l'upload de l'image");
                    setIsSaving(false);
                    return;
                }
            }

            const res = categoryToEdit
                ? await updateCategoryAction(categoryToEdit.id, name, imageUrl)
                : await createCategoryAction(name, imageUrl);

            if (res.success) {
                toast.success(categoryToEdit ? "Catégorie modifiée avec succès" : "Catégorie créée avec succès");
                resetForm();
                onClose();
            } else {
                toast.error(res.error || "Une erreur est survenue");
            }
        } catch (err) {
            toast.error("Erreur de connexion au serveur");
        } finally {
            setIsSaving(false);
        }
    };

    const resetForm = () => {
        setName("");
        setSelectedFile(null);
        setPreviewUrl(null);
    };

    return (
        <Modal
            isOpen={isOpen}
            onClose={onClose}
            backdrop="blur"
            classNames={{
                base: "bg-[#161616] border border-[#262626] rounded-2xl shadow-2xl",
                header: "border-b border-[#262626] px-8 py-5",
                footer: "border-t border-[#262626] px-8 py-6",
            }}
        >
            <ModalContent>
                {(onClose) => (
                    <>
                        <ModalHeader className="flex items-center gap-3">
                            <span className="material-symbols-outlined text-[#ec5b13]">
                                {categoryToEdit ? "edit_note" : "category"}
                            </span>
                            <h2 className="text-slate-100 text-lg font-bold">
                                {categoryToEdit ? "Modifier la Catégorie" : "Nouvelle Catégorie"}
                            </h2>
                        </ModalHeader>
                        <ModalBody className="p-8 space-y-6">
                            <div className="flex flex-col gap-2">
                                <label className="text-slate-400 text-xs font-bold uppercase tracking-widest">Nom de la catégorie</label>
                                <input
                                    className="w-full bg-[#0a0a0a] border border-[#262626] rounded-xl px-4 py-3 text-slate-100 focus:ring-1 focus:ring-[#ec5b13] outline-none transition-all"
                                    placeholder="ex: Cartes Cadeaux"
                                    value={name}
                                    onChange={(e) => setName(e.target.value)}
                                />
                            </div>

                            <div className="flex flex-col gap-2">
                                <label className="text-slate-400 text-xs font-bold uppercase tracking-widest">Image</label>
                                <input
                                    type="file"
                                    ref={fileInputRef}
                                    className="hidden"
                                    accept="image/*"
                                    onChange={handleFileChange}
                                />
                                <div
                                    onClick={() => fileInputRef.current?.click()}
                                    className="aspect-video border-2 border-dashed border-[#262626] bg-[#0a0a0a] rounded-xl flex flex-col items-center justify-center gap-2 cursor-pointer hover:border-[#ec5b13]/50 transition-all group overflow-hidden relative"
                                >
                                    {previewUrl ? (
                                        <img src={previewUrl} className="absolute inset-0 w-full h-full object-cover" alt="Preview" />
                                    ) : (
                                        <>
                                            <span className="material-symbols-outlined text-slate-500 text-3xl group-hover:scale-110 transition-transform">add_photo_alternate</span>
                                            <p className="text-slate-500 text-xs font-medium">Cliquer pour uploader</p>
                                        </>
                                    )}
                                </div>
                            </div>
                        </ModalBody>
                        <ModalFooter>
                            <Button variant="light" onPress={onClose} className="text-slate-400 font-bold">Annuler</Button>
                            <Button
                                className="bg-[#ec5b13] text-white font-bold px-8 shadow-lg shadow-[#ec5b13]/20"
                                onClick={handleSubmit}
                                isLoading={isSaving}
                            >
                                {categoryToEdit ? "Enregistrer" : "Créer la catégorie"}
                            </Button>
                        </ModalFooter>
                    </>
                )}
            </ModalContent>
        </Modal>
    );
};

"use client";

import React, { useState } from "react";
import {
    Modal,
    ModalContent,
    ModalHeader,
    ModalBody,
    ModalFooter,
    Button,
    Input
} from "@heroui/react";
import {
    X,
    Lock,
    Store,
    Package,
    ShieldCheck,
    UserPlus,
    Grid3X3 as Keypad,
    Camera
} from "lucide-react";
import { uploadImage } from "@/app/admin/actions/upload";
import toast from "react-hot-toast";

interface AddMemberModalProps {
    isOpen: boolean;
    onOpenChange: (isOpen: boolean) => void;
}

type Role = "cashier" | "traiteur" | "admin";

import { addUserAction } from "@/app/admin/settings/actions";

export const AddMemberModal = ({ isOpen, onOpenChange }: AddMemberModalProps) => {
    const [fullName, setFullName] = useState("");
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [pinCode, setPinCode] = useState("");
    const [role, setRole] = useState<Role>("cashier");
    const [avatarUrl, setAvatarUrl] = useState<string | null>(null);
    const [selectedFile, setSelectedFile] = useState<File | null>(null);
    const [previewUrl, setPreviewUrl] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const fileInputRef = React.useRef<HTMLInputElement>(null);
    const [error, setError] = useState<string | null>(null);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            setSelectedFile(file);
            setPreviewUrl(URL.createObjectURL(file));
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        setIsLoading(true);
        setError(null);

        let finalAvatarUrl = avatarUrl;
        if (selectedFile) {
            const formData = new FormData();
            formData.append("file", selectedFile);
            const uploadRes = await uploadImage(formData);
            if (uploadRes.success && uploadRes.url) {
                finalAvatarUrl = uploadRes.url;
            } else {
                setError("Échec de l'upload de l'avatar: " + (uploadRes.error || "Erreur inconnue"));
                setIsLoading(false);
                return;
            }
        }

        const result = await addUserAction({
            nom: fullName,
            email,
            password, // will be hashed on server
            pinCode,
            role: role.toUpperCase() as "ADMIN" | "CAISSIER" | "TRAITEUR",
            avatarUrl: finalAvatarUrl
        } as any);

        if (result.success) {
            setIsLoading(false);
            onOpenChange(false);
            toast.success(`${fullName} ajouté à l'équipe`);
            // Reset form
            setFullName("");
            setEmail("");
            setPassword("");
            setPinCode("");
            setRole("cashier");
            setSelectedFile(null);
            setPreviewUrl(null);
        } else {
            setError(result.error || "Une erreur est survenue");
            setIsLoading(false);
        }
    };

    return (
        <Modal
            isOpen={isOpen}
            onOpenChange={onOpenChange}
            size="4xl"
            classNames={{
                base: "bg-[#161616] border border-[#262626] rounded-[24px]",
                header: "border-b border-[#262626] p-6",
                body: "p-6",
                footer: "border-t border-[#262626] p-6",
                closeButton: "hover:bg-[#262626] active:bg-[#262626]/50 transition-colors top-4 right-4"
            }}
            backdrop="blur"
            motionProps={{
                variants: {
                    enter: {
                        y: 0,
                        opacity: 1,
                        transition: {
                            duration: 0.3,
                            ease: "easeOut",
                        },
                    },
                    exit: {
                        y: 20,
                        opacity: 0,
                        transition: {
                            duration: 0.2,
                            ease: "easeIn",
                        },
                    },
                }
            }}
        >
            <ModalContent>
                {(onClose) => (
                    <>
                        <ModalHeader className="flex flex-col gap-1">
                            <h2 className="text-xl font-bold text-slate-100">Nouveau Membre de l'Équipe</h2>
                            <p className="text-sm text-slate-400 font-normal">Créez un accès sécurisé pour votre collaborateur.</p>
                            {error && (
                                <div className="mt-4 p-3 bg-red-500/10 border border-red-500/20 rounded-xl text-red-500 text-sm font-medium">
                                    {error}
                                </div>
                            )}
                        </ModalHeader>
                        <form onSubmit={handleSubmit}>
                            <ModalBody className="gap-6">
                                {/* Avatar Section */}
                                <div className="flex flex-col items-center gap-4 mb-2">
                                    <div className="relative group cursor-pointer" onClick={() => fileInputRef.current?.click()}>
                                        <div className="size-24 rounded-full overflow-hidden border-2 border-[#262626] bg-[#0a0a0a] flex items-center justify-center">
                                            {previewUrl ? (
                                                <img src={previewUrl} className="w-full h-full object-cover" alt="Avatar" />
                                            ) : (
                                                <Camera className="w-10 h-10 text-slate-700 group-hover:text-[#ec5b13] transition-colors" />
                                            )}
                                        </div>
                                        <div className="absolute inset-0 bg-black/40 rounded-full opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                                            <span className="text-white text-[10px] font-bold uppercase">Changer</span>
                                        </div>
                                    </div>
                                    <input
                                        type="file"
                                        ref={fileInputRef}
                                        className="hidden"
                                        accept="image/*"
                                        onChange={handleFileChange}
                                    />
                                    <p className="text-xs text-slate-500 font-medium">Photo de profil du collaborateur (optionnel)</p>
                                </div>

                                {/* Personal Info Section */}
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <label className="block text-sm font-medium text-slate-400" htmlFor="full_name">Nom complet</label>
                                        <input
                                            className="w-full bg-[#0a0a0a] border border-[#262626] rounded-xl text-slate-100 placeholder:text-slate-600 focus:ring-[#ec5b13] focus:border-[#ec5b13] transition-all p-3 outline-none"
                                            id="full_name"
                                            placeholder="Ex: Amine Caissier"
                                            type="text"
                                            value={fullName}
                                            onChange={(e) => setFullName(e.target.value)}
                                            required
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <label className="block text-sm font-medium text-slate-400" htmlFor="email">Adresse Email</label>
                                        <input
                                            className="w-full bg-[#0a0a0a] border border-[#262626] rounded-xl text-slate-100 placeholder:text-slate-600 focus:ring-[#ec5b13] focus:border-[#ec5b13] transition-all p-3 outline-none"
                                            id="email"
                                            placeholder="amine@flexbox-direct.com"
                                            type="email"
                                            value={email}
                                            onChange={(e) => setEmail(e.target.value)}
                                            required
                                        />
                                    </div>
                                </div>

                                {/* Security Section */}
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <label className="block text-sm font-medium text-slate-400" htmlFor="password">Mot de passe</label>
                                        <div className="relative">
                                            <input
                                                className="w-full bg-[#0a0a0a] border border-[#262626] rounded-xl text-slate-100 placeholder:text-slate-600 focus:ring-[#ec5b13] focus:border-[#ec5b13] transition-all pl-10 p-3 outline-none"
                                                id="password"
                                                placeholder="••••••••"
                                                type="password"
                                                value={password}
                                                onChange={(e) => setPassword(e.target.value)}
                                                required
                                            />
                                            <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                                        </div>
                                    </div>
                                    <div className="space-y-2">
                                        <label className="block text-sm font-medium text-slate-400" htmlFor="pin_code">Code PIN Rapide (4 chiffres)</label>
                                        <div className="relative">
                                            <input
                                                className="w-full bg-[#0a0a0a] border border-[#262626] rounded-xl text-slate-100 placeholder:text-slate-600 focus:ring-[#ec5b13] focus:border-[#ec5b13] transition-all pl-10 p-3 outline-none tracking-[0.5em]"
                                                id="pin_code"
                                                maxLength={4}
                                                placeholder="0000"
                                                type="text"
                                                value={pinCode}
                                                onChange={(e) => setPinCode(e.target.value)}
                                                required
                                            />
                                            <Keypad className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                                        </div>
                                    </div>
                                </div>

                                {/* Role Selection Section */}
                                <div>
                                    <h3 className="text-sm font-medium text-slate-400 mb-3">Niveau d'accès</h3>
                                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                        {/* Role: Cashier */}
                                        <button
                                            type="button"
                                            onClick={() => setRole("cashier")}
                                            className={`relative flex flex-col p-4 text-left rounded-xl transition-all group border-2 ${role === "cashier"
                                                ? "border-[#ec5b13] bg-[#ec5b13]/10"
                                                : "border-[#262626] bg-[#0a0a0a] hover:border-slate-700"
                                                }`}
                                        >
                                            <div className="flex items-center justify-between mb-3 w-full">
                                                <div className={`p-2 rounded-lg shrink-0 ${role === "cashier" ? "bg-[#ec5b13]/20 text-[#ec5b13]" : "bg-zinc-800 text-slate-400 group-hover:text-slate-100"
                                                    }`}>
                                                    <Store className="w-6 h-6" />
                                                </div>
                                                <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center ${role === "cashier" ? "border-[#ec5b13]" : "border-slate-700"
                                                    }`}>
                                                    {role === "cashier" && <div className="w-2 h-2 rounded-full bg-[#ec5b13]"></div>}
                                                </div>
                                            </div>
                                            <span className="text-slate-100 font-bold block">Caissier</span>
                                            <span className="text-xs text-slate-500 mt-2 leading-relaxed">
                                                Accès limité à la Borne, la Caisse et le Traitement. Ne voit pas les bénéfices ni les fournisseurs.
                                            </span>
                                        </button>

                                        {/* Role: Traiteur */}
                                        <button
                                            type="button"
                                            onClick={() => setRole("traiteur")}
                                            className={`relative flex flex-col p-4 text-left rounded-xl transition-all group border-2 ${role === "traiteur"
                                                ? "border-[#ec5b13] bg-[#ec5b13]/10"
                                                : "border-[#262626] bg-[#0a0a0a] hover:border-slate-700"
                                                }`}
                                        >
                                            <div className="flex items-center justify-between mb-3 w-full">
                                                <div className={`p-2 rounded-lg shrink-0 ${role === "traiteur" ? "bg-[#ec5b13]/20 text-[#ec5b13]" : "bg-zinc-800 text-slate-400 group-hover:text-slate-100"
                                                    }`}>
                                                    <Package className="w-6 h-6" />
                                                </div>
                                                <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center ${role === "traiteur" ? "border-[#ec5b13]" : "border-slate-700"
                                                    }`}>
                                                    {role === "traiteur" && <div className="w-2 h-2 rounded-full bg-[#ec5b13]"></div>}
                                                </div>
                                            </div>
                                            <span className="text-slate-100 font-bold block">Traiteur de commande</span>
                                            <span className="text-xs text-slate-500 mt-2 leading-relaxed">
                                                Accès au catalogue et au traitement des commandes uniquement. Ne voit pas la caisse ni les finances.
                                            </span>
                                        </button>

                                        {/* Role: Administrator */}
                                        <button
                                            type="button"
                                            onClick={() => setRole("admin")}
                                            className={`relative flex flex-col p-4 text-left rounded-xl transition-all group border-2 ${role === "admin"
                                                ? "border-[#ec5b13] bg-[#ec5b13]/10"
                                                : "border-[#262626] bg-[#0a0a0a] hover:border-slate-700"
                                                }`}
                                        >
                                            <div className="flex items-center justify-between mb-3 w-full">
                                                <div className={`p-2 rounded-lg shrink-0 ${role === "admin" ? "bg-[#ec5b13]/20 text-[#ec5b13]" : "bg-zinc-800 text-slate-400 group-hover:text-slate-100"
                                                    }`}>
                                                    <ShieldCheck className="w-6 h-6" />
                                                </div>
                                                <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center ${role === "admin" ? "border-[#ec5b13]" : "border-slate-700"
                                                    }`}>
                                                    {role === "admin" && <div className="w-2 h-2 rounded-full bg-[#ec5b13]"></div>}
                                                </div>
                                            </div>
                                            <span className="text-slate-100 font-bold block">Administrateur</span>
                                            <span className="text-xs text-slate-500 mt-2 leading-relaxed">
                                                Contrôle total du système, accès aux finances et aux réglages.
                                            </span>
                                        </button>
                                    </div>
                                </div>
                            </ModalBody>
                            <ModalFooter>
                                <Button
                                    variant="light"
                                    onPress={onClose}
                                    className="text-slate-400 hover:text-white font-medium"
                                >
                                    Annuler
                                </Button>
                                <Button
                                    className="bg-[#ec5b13] hover:bg-[#ff6d24] text-white px-8 rounded-xl font-bold shadow-lg shadow-orange-900/20 active:scale-95 transition-all"
                                    type="submit"
                                    isLoading={isLoading}
                                    startContent={!isLoading && <UserPlus className="w-5 h-5" />}
                                >
                                    Créer le compte
                                </Button>
                            </ModalFooter>
                        </form>
                    </>
                )}
            </ModalContent>
        </Modal>
    );
};

"use client";

import React, { useState } from "react";
import {
    Modal,
    ModalContent,
    ModalHeader,
    ModalBody,
    ModalFooter,
    Button,
    Input,
    Select,
    SelectItem,
    Textarea,
    Switch
} from "@heroui/react";

import { createProductAction, updateProductAction } from "@/app/admin/catalogue/actions";
import { uploadImage } from "@/app/admin/actions/upload";

import { toast } from "react-hot-toast";

interface LinkedSupplier {
    id: string;
    supplierId: string;
    purchasePrice: string;
    currency: string;
}

interface Variant {
    id: string;
    name: string;
    purchasePrice: string;
    salePrice: string;
    linkedSuppliers: LinkedSupplier[];
}

interface AddProductModalProps {
    isOpen: boolean;
    onClose: () => void;
    categories: any[];
    suppliers: any[];
    productToEdit?: any | null;
}

export const AddProductModal = ({ isOpen, onClose, categories, suppliers, productToEdit }: AddProductModalProps) => {
    const [isSaving, setIsSaving] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [name, setName] = useState("");
    const [description, setDescription] = useState("");
    const [categoryId, setCategoryId] = useState("");
    const [imageUrl, setImageUrl] = useState<string | null>(null);
    const [selectedFile, setSelectedFile] = useState<File | null>(null);
    const [previewUrl, setPreviewUrl] = useState<string | null>(null);
    const [requiresPlayerId, setRequiresPlayerId] = useState(false);
    const fileInputRef = React.useRef<HTMLInputElement>(null);

    const [variants, setVariants] = useState<Variant[]>([
        {
            id: Math.random().toString(),
            name: "Standard Edition",
            purchasePrice: "0.00",
            salePrice: "0.00",
            linkedSuppliers: []
        }
    ]);

    // Initialize state when modal opens or productToEdit changes
    React.useEffect(() => {
        if (productToEdit && isOpen) {
            setName(productToEdit.name || "");
            setDescription(productToEdit.description || "");
            setCategoryId(productToEdit.categoryId?.toString() || "");
            setImageUrl(productToEdit.imageUrl);
            setPreviewUrl(productToEdit.imageUrl);
            setRequiresPlayerId(productToEdit.requiresPlayerId || false);
            setSelectedFile(null);

            if (productToEdit.variants && productToEdit.variants.length > 0) {
                setVariants(productToEdit.variants.map((v: any) => ({
                    id: v.id?.toString() || Math.random().toString(),
                    name: v.name || "",
                    purchasePrice: v.purchasePriceUsd || "0.00",
                    salePrice: v.salePriceDzd || "0.00",
                    linkedSuppliers: (v.variantSuppliers || []).map((ls: any) => ({
                        id: Math.random().toString(),
                        supplierId: ls.supplierId?.toString() || "",
                        purchasePrice: ls.purchasePrice || "0.00",
                        currency: ls.currency || "USD"
                    }))
                })));
            } else {
                setVariants([{
                    id: Math.random().toString(),
                    name: "Standard Edition",
                    purchasePrice: "0.00",
                    salePrice: "0.00",
                    linkedSuppliers: []
                }]);
            }
        } else if (!productToEdit && isOpen) {
            resetForm();
        }
    }, [productToEdit, isOpen]);

    const resetForm = () => {
        setName("");
        setDescription("");
        setCategoryId("");
        setImageUrl(null);
        setPreviewUrl(null);
        setSelectedFile(null);
        setRequiresPlayerId(false);
        setVariants([
            {
                id: Math.random().toString(),
                name: "Standard Edition",
                purchasePrice: "0.00",
                salePrice: "0.00",
                linkedSuppliers: []
            }
        ]);
        setError(null);
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            setSelectedFile(file);
            const url = URL.createObjectURL(file);
            setPreviewUrl(url);
        }
    };

    const handleSubmit = async () => {
        if (!name || !categoryId) {
            const msg = "Veuillez remplir les champs obligatoires (Nom et Catégorie)";
            setError(msg);
            toast.error(msg);
            return;
        }

        setIsSaving(true);
        setError(null);

        let finalImageUrl = imageUrl;

        try {
            // Upload image if selected
            if (selectedFile) {
                const formData = new FormData();
                formData.append("file", selectedFile);
                const uploadRes = await uploadImage(formData);
                if (uploadRes.success && uploadRes.url) {
                    finalImageUrl = uploadRes.url;
                } else {
                    const msg = "Échec de l'upload de l'image: " + (uploadRes.error || "Erreur inconnue");
                    setError(msg);
                    toast.error(msg);
                    setIsSaving(false);
                    return;
                }
            }

            const productData = {
                name,
                description,
                categoryId: parseInt(categoryId),
                imageUrl: finalImageUrl,
                requiresPlayerId,
                variants: variants.map(v => ({
                    name: v.name,
                    purchasePriceUsd: v.purchasePrice,
                    salePriceDzd: v.salePrice,
                    linkedSuppliers: (v.linkedSuppliers || []).map(ls => ({
                        supplierId: parseInt(ls.supplierId),
                        purchasePrice: ls.purchasePrice,
                        currency: ls.currency
                    }))
                }))
            };

            const res = productToEdit
                ? await updateProductAction(productToEdit.id, productData)
                : await createProductAction(productData);

            if (res.success) {
                toast.success(productToEdit ? "Produit modifié avec succès" : "Produit ajouté avec succès");
                onClose();
                if (!productToEdit) resetForm();
            } else {
                const msg = res.error || "Une erreur est survenue";
                setError(msg);
                toast.error(msg);
            }
        } catch (err) {
            const msg = "Erreur de connexion au serveur";
            setError(msg);
            toast.error(msg);
        } finally {
            setIsSaving(false);
        }
    };

    const addVariant = () => {
        setVariants([...variants, {
            id: Math.random().toString(),
            name: "",
            purchasePrice: "",
            salePrice: "",
            linkedSuppliers: []
        }]);
    };

    const removeVariant = (id: string) => {
        if (variants.length > 1) {
            setVariants(variants.filter(v => v.id !== id));
        }
    };

    const updateVariant = (id: string, field: keyof Variant, value: any) => {
        setVariants(variants.map(v => v.id === id ? { ...v, [field]: value } : v));
    };

    const addLinkedSupplier = (variantId: string) => {
        const variant = variants.find(v => v.id === variantId);
        if (variant) {
            const newSuppliers = [
                ...variant.linkedSuppliers,
                { id: Math.random().toString(), supplierId: "", purchasePrice: "0.00", currency: "USD" }
            ];
            updateVariant(variantId, "linkedSuppliers", newSuppliers);
        }
    };

    const removeLinkedSupplier = (variantId: string, supplierEntryId: string) => {
        const variant = variants.find(v => v.id === variantId);
        if (variant) {
            const newSuppliers = variant.linkedSuppliers.filter(s => s.id !== supplierEntryId);
            updateVariant(variantId, "linkedSuppliers", newSuppliers);
        }
    };

    const updateLinkedSupplier = (variantId: string, supplierEntryId: string, field: keyof LinkedSupplier, value: string) => {
        const variant = variants.find(v => v.id === variantId);
        if (variant) {
            const newSuppliers = variant.linkedSuppliers.map(s => {
                if (s.id === supplierEntryId) {
                    const update: any = { ...s, [field]: value };
                    if (field === "supplierId") {
                        const selectedSup = suppliers.find(sup => sup.id.toString() === value);
                        if (selectedSup) {
                            update.currency = selectedSup.baseCurrency || "USD";
                        }
                    }
                    return update;
                }
                return s;
            });
            updateVariant(variantId, "linkedSuppliers", newSuppliers);
        }
    };

    return (
        <>
            <style jsx global>{`
                .custom-scrollbar::-webkit-scrollbar {
                    width: 6px;
                }
                .custom-scrollbar::-webkit-scrollbar-track {
                    background: transparent;
                }
                .custom-scrollbar::-webkit-scrollbar-thumb {
                    background: #262626;
                    border-radius: 10px;
                }
                .custom-scrollbar::-webkit-scrollbar-thumb:hover {
                    background: #333333;
                }
            `}</style>

            <Modal
                isOpen={isOpen}
                onClose={onClose}
                backdrop="blur"
                size="4xl"
                classNames={{
                    base: "bg-[#161616] border border-[#262626] rounded-2xl shadow-2xl overflow-hidden",
                    header: "border-b border-[#262626] px-8 py-5",
                    footer: "border-t border-[#262626] px-8 py-6 bg-[#161616]/80 backdrop-blur-md",
                    closeButton: "hover:bg-white/5 active:bg-white/10 transition-colors top-4 right-4 rounded-full size-10",
                }}
            >
                <ModalContent>
                    {(onClose) => (
                        <>
                            <ModalHeader>
                                <div className="flex items-center gap-3">
                                    <span className="material-symbols-outlined text-[#ec5b13] text-2xl">{productToEdit ? "edit_square" : "add_box"}</span>
                                    <h2 className="text-slate-100 text-lg font-bold leading-tight tracking-tight">
                                        {productToEdit ? "Modifier le Produit" : "Ajouter un Nouveau Produit"}
                                    </h2>
                                </div>
                                {error && (
                                    <p className="mt-2 text-red-500 text-xs font-bold uppercase tracking-wider">{error}</p>
                                )}
                            </ModalHeader>

                            <ModalBody className="p-8 custom-scrollbar">
                                <div className="flex flex-col gap-10">
                                    {/* Section 1: General Info */}
                                    <section className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                        {/* Left Column: Image Upload */}
                                        <div className="flex flex-col gap-3">
                                            <p className="text-slate-400 text-sm font-medium">Image du Produit</p>
                                            <input
                                                type="file"
                                                ref={fileInputRef}
                                                className="hidden"
                                                accept="image/*"
                                                onChange={handleFileChange}
                                            />
                                            <div
                                                onClick={() => fileInputRef.current?.click()}
                                                className="flex-1 min-h-[240px] border-2 border-dashed border-[#262626] bg-[#0a0a0a] rounded-xl flex flex-col items-center justify-center gap-4 cursor-pointer hover:border-[#ec5b13]/50 transition-all group p-6 relative overflow-hidden"
                                            >
                                                {previewUrl ? (
                                                    <img src={previewUrl} className="absolute inset-0 w-full h-full object-cover" alt="Preview" />
                                                ) : (
                                                    <>
                                                        <div className="size-16 rounded-full bg-white/5 flex items-center justify-center group-hover:scale-110 transition-transform">
                                                            <span className="material-symbols-outlined text-slate-400 text-3xl group-hover:text-[#ec5b13]">image</span>
                                                        </div>
                                                        <div className="text-center">
                                                            <p className="text-slate-100 text-sm font-semibold">Glissez l'image ou cliquez pour parcourir</p>
                                                            <p className="text-slate-500 text-xs mt-1">PNG, JPG jusqu'à 10MB</p>
                                                        </div>
                                                    </>
                                                )}
                                                {previewUrl && (
                                                    <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                                                        <span className="text-white font-bold text-sm">Changer l'image</span>
                                                    </div>
                                                )}
                                            </div>
                                        </div>

                                        {/* Right Column: Form Fields */}
                                        <div className="flex flex-col gap-5">
                                            <div className="flex flex-col gap-2">
                                                <label className="text-slate-400 text-sm font-medium">Nom du Produit</label>
                                                <input
                                                    className="w-full bg-[#0a0a0a] border border-[#262626] rounded-xl px-4 py-3 text-slate-100 placeholder:text-slate-600 focus:ring-1 focus:ring-[#ec5b13] focus:border-[#ec5b13] outline-none transition-all"
                                                    placeholder="ex: Dashboard UI Kit"
                                                    type="text"
                                                    value={name}
                                                    onChange={(e) => setName(e.target.value)}
                                                />
                                            </div>

                                            <div className="flex flex-col gap-2">
                                                <label className="text-slate-400 text-sm font-medium">Catégorie</label>
                                                <div className="relative group">
                                                    <select
                                                        className="w-full bg-[#0a0a0a] border border-[#262626] rounded-xl px-4 py-3 text-slate-100 appearance-none focus:ring-1 focus:ring-[#ec5b13] focus:border-[#ec5b13] outline-none transition-all cursor-pointer"
                                                        value={categoryId}
                                                        onChange={(e) => setCategoryId(e.target.value)}
                                                    >
                                                        <option disabled value="">Sélectionner une catégorie</option>
                                                        {categories.map(cat => (
                                                            <option key={cat.id} value={String(cat.id)}>{cat.name}</option>
                                                        ))}
                                                    </select>
                                                    <span className="material-symbols-outlined absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none group-focus-within:text-[#ec5b13] transition-colors">expand_more</span>
                                                </div>
                                            </div>

                                            <div className="flex flex-col gap-2">
                                                <label className="text-slate-400 text-sm font-medium">Description</label>
                                                <textarea
                                                    className="w-full bg-[#0a0a0a] border border-[#262626] rounded-xl px-4 py-3 text-slate-100 placeholder:text-slate-600 focus:ring-1 focus:ring-[#ec5b13] focus:border-[#ec5b13] outline-none transition-all resize-none h-[115px]"
                                                    placeholder="Décrivez les fonctionnalités clés du produit..."
                                                    value={description}
                                                    onChange={(e) => setDescription(e.target.value)}
                                                ></textarea>
                                            </div>

                                            <div className="flex items-center justify-between p-4 bg-[#0a0a0a] border border-[#262626] rounded-xl">
                                                <div className="flex flex-col gap-0.5">
                                                    <span className="text-slate-100 text-sm font-bold uppercase tracking-tight">Direct Top-up</span>
                                                    <span className="text-slate-500 text-[10px] font-bold uppercase tracking-wider">Nécessite un ID Joueur / Lien</span>
                                                </div>
                                                <Switch
                                                    isSelected={requiresPlayerId}
                                                    onValueChange={setRequiresPlayerId}
                                                    color="primary"
                                                />
                                            </div>
                                        </div>
                                    </section>

                                    {/* Section 2: Variants & Pricing */}
                                    <section className="flex flex-col gap-6">
                                        <div className="flex items-center justify-between">
                                            <h3 className="text-slate-100 font-bold flex items-center gap-2">
                                                <span className="material-symbols-outlined text-[#ec5b13]">layers</span>
                                                Variantes du Produit
                                            </h3>
                                        </div>

                                        <div className="space-y-6">
                                            {variants.map((v) => (
                                                <div key={v.id} className="bg-[#0a0a0a] border border-[#262626] rounded-xl p-6 flex flex-col gap-6 group relative shadow-lg">
                                                    {/* Variant Main Info Row */}
                                                    <div className="flex flex-col md:flex-row items-end gap-4 w-full">
                                                        <div className="flex-1 w-full flex flex-col gap-2">
                                                            <label className="text-slate-500 text-xs font-semibold uppercase tracking-wider">Nom de la variante</label>
                                                            <input
                                                                className="w-full bg-black/40 border border-[#262626] rounded-lg px-4 py-2.5 text-slate-100 focus:ring-1 focus:ring-[#ec5b13] outline-none"
                                                                placeholder="Standard Edition"
                                                                type="text"
                                                                value={v.name}
                                                                onChange={(e) => updateVariant(v.id, "name", e.target.value)}
                                                            />
                                                        </div>
                                                        <div className="w-full md:w-48 flex flex-col gap-2">
                                                            <label className="text-slate-500 text-xs font-semibold uppercase tracking-wider">Prix d'achat (USD)</label>
                                                            <div className="relative">
                                                                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 font-medium">$</span>
                                                                <input
                                                                    className="w-full bg-black/40 border border-[#262626] rounded-lg pl-8 pr-4 py-2.5 text-slate-100 focus:ring-1 focus:ring-[#ec5b13] outline-none"
                                                                    placeholder="0.00"
                                                                    type="number"
                                                                    value={v.purchasePrice}
                                                                    onChange={(e) => updateVariant(v.id, "purchasePrice", e.target.value)}
                                                                />
                                                            </div>
                                                        </div>
                                                        <div className="w-full md:w-48 flex flex-col gap-2">
                                                            <label className="text-slate-500 text-xs font-semibold uppercase tracking-wider">Prix de vente (DZD)</label>
                                                            <div className="relative">
                                                                <input
                                                                    className="w-full bg-black/40 border border-[#262626] rounded-lg pl-4 pr-16 py-2.5 text-slate-100 focus:ring-1 focus:ring-[#ec5b13] outline-none"
                                                                    placeholder="0.00"
                                                                    type="number"
                                                                    value={v.salePrice}
                                                                    onChange={(e) => updateVariant(v.id, "salePrice", e.target.value)}
                                                                />
                                                                <span className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 font-medium text-xs whitespace-nowrap">DZD</span>
                                                            </div>
                                                        </div>
                                                        <button
                                                            onClick={() => removeVariant(v.id)}
                                                            className="size-11 flex items-center justify-center rounded-lg bg-red-500/10 text-red-500 hover:bg-red-500 hover:text-white transition-all shrink-0 active:scale-90"
                                                        >
                                                            <span className="material-symbols-outlined text-xl">delete</span>
                                                        </button>
                                                    </div>

                                                    {/* Linked Suppliers Sub-section */}
                                                    <div className="flex flex-col gap-4 pt-4 border-t border-[#262626]/50">
                                                        <div className="flex items-center justify-between">
                                                            <h4 className="text-slate-400 text-xs font-bold uppercase tracking-widest flex items-center gap-2">
                                                                <span className="material-symbols-outlined text-sm">link</span>
                                                                Fournisseurs Liés
                                                            </h4>
                                                        </div>

                                                        <div className="flex flex-col gap-3">
                                                            {v.linkedSuppliers.map((ls) => (
                                                                <div key={ls.id} className="flex flex-col md:flex-row items-center gap-3 bg-black/20 p-3 rounded-lg border border-[#262626]/30">
                                                                    <div className="flex-1 w-full relative">
                                                                        <select
                                                                            value={ls.supplierId}
                                                                            onChange={(e) => updateLinkedSupplier(v.id, ls.id, "supplierId", e.target.value)}
                                                                            className="w-full bg-black/40 border border-[#262626] rounded-lg px-3 py-2 text-slate-100 text-sm appearance-none focus:ring-1 focus:ring-[#ec5b13] outline-none transition-all cursor-pointer"
                                                                        >
                                                                            <option value="" disabled>Choisir un fournisseur</option>
                                                                            {suppliers.map(s => (
                                                                                <option key={s.id} value={s.id}>{s.name}</option>
                                                                            ))}
                                                                        </select>
                                                                        <span className="material-symbols-outlined absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 text-lg pointer-events-none">expand_more</span>
                                                                    </div>
                                                                    <div className="w-full md:w-40 relative">
                                                                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 text-xs">
                                                                            {ls.currency === "DZD" ? "" : "$"}
                                                                        </span>
                                                                        <input
                                                                            className={`w-full bg-black/40 border border-[#262626] rounded-lg ${ls.currency === "DZD" ? "pr-10 pl-3" : "pl-6 pr-3"} py-2 text-slate-100 text-sm focus:ring-1 focus:ring-[#ec5b13] outline-none`}
                                                                            placeholder="Prix d'achat"
                                                                            type="number"
                                                                            value={ls.purchasePrice}
                                                                            onChange={(e) => updateLinkedSupplier(v.id, ls.id, "purchasePrice", e.target.value)}
                                                                        />
                                                                        {ls.currency === "DZD" && (
                                                                            <span className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 text-[10px] font-bold">DZD</span>
                                                                        )}
                                                                    </div>
                                                                    <button
                                                                        onClick={() => removeLinkedSupplier(v.id, ls.id)}
                                                                        className="text-slate-500 hover:text-red-400 transition-colors px-1"
                                                                    >
                                                                        <span className="material-symbols-outlined text-lg">close</span>
                                                                    </button>
                                                                </div>
                                                            ))}
                                                        </div>

                                                        {/* Add Supplier Button */}
                                                        <button
                                                            onClick={() => addLinkedSupplier(v.id)}
                                                            className="flex items-center gap-2 text-xs font-bold text-[#ec5b13]/80 hover:text-[#ec5b13] transition-colors w-fit group/add"
                                                        >
                                                            <span className="material-symbols-outlined text-sm group-hover/add:scale-110 transition-transform">add_circle</span>
                                                            Lier un fournisseur
                                                        </button>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>

                                        {/* Add Variant Ghost Button */}
                                        <button
                                            onClick={addVariant}
                                            className="flex items-center justify-center gap-2 py-4 border-2 border-dashed border-[#ec5b13]/20 rounded-xl text-[#ec5b13] font-bold hover:bg-[#ec5b13]/5 hover:border-[#ec5b13]/40 transition-all active:scale-[0.99]"
                                        >
                                            <span className="material-symbols-outlined">add_circle</span>
                                            Ajouter une autre variante
                                        </button>
                                    </section>
                                </div>
                            </ModalBody>

                            <ModalFooter>
                                <button
                                    className="px-6 py-3 rounded-xl text-slate-400 font-semibold hover:text-white hover:bg-white/5 transition-all"
                                    onClick={onClose}
                                >
                                    Annuler
                                </button>
                                <button
                                    className="px-10 py-3 bg-[#ec5b13] text-white font-bold rounded-xl shadow-lg shadow-[#ec5b13]/20 hover:bg-[#ec5b13]/90 hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center gap-2"
                                    onClick={handleSubmit}
                                    disabled={isSaving}
                                >
                                    {isSaving ? (productToEdit ? "Mise à jour..." : "Création...") : (
                                        <>
                                            {productToEdit ? "Enregistrer les modifications" : "Créer le Produit"}
                                            <span className="material-symbols-outlined text-xl">{productToEdit ? "save" : "rocket_launch"}</span>
                                        </>
                                    )}
                                </button>
                            </ModalFooter>
                        </>
                    )}
                </ModalContent>
            </Modal>
        </>
    );
};

"use client";

import React, { useState } from "react";
import {
    Modal,
    ModalContent,
    ModalHeader,
    ModalBody,
    ModalFooter,
    Button,
    Table,
    TableHeader,
    TableColumn,
    TableBody,
    TableRow,
    TableCell,
    Tooltip
} from "@heroui/react";
import { Edit2, Trash2 } from "lucide-react";
import { deleteCategoryAction } from "@/app/admin/catalogue/actions";
import { toast } from "react-hot-toast";

interface Category {
    id: number;
    name: string;
    icon: string | null;
    imageUrl: string | null;
}

interface ManageCategoriesModalProps {
    isOpen: boolean;
    onClose: () => void;
    categories: Category[];
    onEdit: (category: Category) => void;
}

export const ManageCategoriesModal = ({ isOpen, onClose, categories, onEdit }: ManageCategoriesModalProps) => {
    const [isDeleting, setIsDeleting] = useState<number | null>(null);

    const handleDelete = async (id: number) => {
        if (!confirm("Êtes-vous sûr de vouloir supprimer cette catégorie ? Les produits associés ne seront pas supprimés mais n'auront plus de catégorie.")) {
            return;
        }

        setIsDeleting(id);
        try {
            const res = await deleteCategoryAction(id);
            if (res.success) {
                toast.success("Catégorie supprimée");
            } else {
                toast.error(res.error || "Erreur lors de la suppression");
            }
        } catch (err) {
            toast.error("Erreur de connexion");
        } finally {
            setIsDeleting(null);
        }
    };

    return (
        <Modal
            isOpen={isOpen}
            onClose={onClose}
            size="2xl"
            backdrop="blur"
            classNames={{
                base: "bg-[#161616] border border-[#262626] rounded-2xl shadow-2xl",
                header: "border-b border-[#262626] px-8 py-5",
                footer: "border-t border-[#262626] px-8 py-6",
            }}
        >
            <ModalContent>
                {(onClose) => (
                    <>
                        <ModalHeader className="flex items-center gap-3">
                            <span className="material-symbols-outlined text-[#ec5b13]">settings_suggest</span>
                            <h2 className="text-slate-100 text-lg font-bold">Gérer les Catégories</h2>
                        </ModalHeader>
                        <ModalBody className="p-0">
                            <Table
                                aria-label="Liste des catégories"
                                className="bg-transparent"
                                removeWrapper
                                classNames={{
                                    th: "bg-[#262626]/50 text-slate-500 font-black uppercase text-[10px] tracking-widest px-8 py-4",
                                    td: "px-8 py-4 text-slate-300 border-b border-[#262626]/50",
                                }}
                            >
                                <TableHeader>
                                    <TableColumn>CATÉGORIE</TableColumn>
                                    <TableColumn align="center">IMAGE</TableColumn>
                                    <TableColumn align="end">ACTIONS</TableColumn>
                                </TableHeader>
                                <TableBody>
                                    {categories.map((cat) => (
                                        <TableRow key={cat.id} className="hover:bg-white/5 transition-colors">
                                            <TableCell>
                                                <span className="font-bold text-sm tracking-tight">{cat.name}</span>
                                            </TableCell>
                                            <TableCell>
                                                <div className="flex justify-center">
                                                    {cat.imageUrl ? (
                                                        <div className="size-10 rounded-lg overflow-hidden border border-white/5">
                                                            <img src={cat.imageUrl} alt={cat.name} className="w-full h-full object-cover" />
                                                        </div>
                                                    ) : (
                                                        <div className="size-10 rounded-lg bg-[#262626] flex items-center justify-center border border-white/5">
                                                            <span className="material-symbols-outlined text-slate-500 text-lg">category</span>
                                                        </div>
                                                    )}
                                                </div>
                                            </TableCell>
                                            <TableCell>
                                                <div className="flex justify-end gap-3">
                                                    <Tooltip content="Modifier" color="primary">
                                                        <Button
                                                            isIconOnly
                                                            size="sm"
                                                            variant="flat"
                                                            className="bg-primary/10 text-primary hover:bg-primary hover:text-white"
                                                            onClick={() => onEdit(cat)}
                                                        >
                                                            <Edit2 size={16} />
                                                        </Button>
                                                    </Tooltip>
                                                    <Tooltip content="Supprimer" color="danger">
                                                        <Button
                                                            isIconOnly
                                                            size="sm"
                                                            variant="flat"
                                                            color="danger"
                                                            className="bg-red-500/10 text-red-500 hover:bg-red-500 hover:text-white"
                                                            isLoading={isDeleting === cat.id}
                                                            onClick={() => handleDelete(cat.id)}
                                                        >
                                                            <Trash2 size={16} />
                                                        </Button>
                                                    </Tooltip>
                                                </div>
                                            </TableCell>
                                        </TableRow>
                                    ))}
                                </TableBody>
                            </Table>
                            {categories.length === 0 && (
                                <div className="py-12 text-center">
                                    <p className="text-slate-500 text-sm italic">Aucune catégorie trouvée.</p>
                                </div>
                            )}
                        </ModalBody>
                        <ModalFooter>
                            <Button variant="flat" onPress={onClose} className="bg-[#262626] text-white font-bold px-8">
                                Fermer
                            </Button>
                        </ModalFooter>
                    </>
                )}
            </ModalContent>
        </Modal>
    );
};
